BEGIN;

INSERT INTO courses (
    course_code,
    course_name,
    class_number,
    status,
    meeting_time,
    room,
    instructor,
    open_seats,
    component_type,
    type,
    credits,
    building,
    combined_classes,
    course_description,
    class_attributes,
    enrollment_requirements
) VALUES
    ('EDUC-K 306', 'TEACHING STUDENTS WITH SPECIAL NEEDS IN SECONDARY CLASSROOMS', '1522', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 0101', 'Theresa Ochoa, Nell Krahnke', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course includes an overview of the skills and knowledge necessary for effective instruction of students with disabilities in inclusive secondary programs.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-K 344', 'INDIVIDUALIZED BEHAVIOR INTERVENTIONS AND SUPPORTS', '12308', 'Class Status', 'F Friday 11:10 AM–12:25 PM', 'ED 2275', 'Sarah Hurwitz', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes specialized knowledge and skills necessary to develop school and community-based supports for students with behavioral challenges. Focuses on how to conduct functional behavioral assessments and develop and implement positive behavior intervention plans.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 344', 'INDIVIDUALIZED BEHAVIOR INTERVENTIONS AND SUPPORTS', '14318', 'Class Status', 'F Friday 11:10 AM–12:25 PM', 'ED 2275', 'Sarah Hurwitz', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasizes specialized knowledge and skills necessary to develop school and community-based supports for students with behavioral challenges. Focuses on how to conduct functional behavioral assessments and develop and implement positive behavior intervention plans.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 352', 'SPECIALLY DESIGNED INSTRUCTION FOR STUDENTS WITH MILD TO MODERATE DISABILITIES', '6249', 'Class Status', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'ED 2025', 'Susan Klinker', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focuses on research-based methods for teaching individuals with mild/moderate disabilities, including the selection, implementation, and adaptation of evidence-based instructional programs, strategies, and materials. Emphasizes federal and state laws and procedures for developing and implementing Individualized Education Plans.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 352', 'SPECIALLY DESIGNED INSTRUCTION FOR STUDENTS WITH MILD TO MODERATE DISABILITIES', '32307', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'ED 2025', 'Susan Klinker', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focuses on research-based methods for teaching individuals with mild/moderate disabilities, including the selection, implementation, and adaptation of evidence-based instructional programs, strategies, and materials. Emphasizes federal and state laws and procedures for developing and implementing Individualized Education Plans.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 361', 'ASSISTIVE TECHNOLOGY FOR ELEMENTARY SCHOOL STUDENTS WITH DISABILITIES', '12610', 'Class Status', 'F Friday 9:35 AM–10:50 AM', 'ED 2275', 'Richard Carter', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to prepare future teachers with the knowledge required to integrate assistive technology into curricula for students with mild to moderate disabilities.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 361', 'ASSISTIVE TECHNOLOGY FOR ELEMENTARY SCHOOL STUDENTS WITH DISABILITIES', '5492', 'Class Status', 'F Friday 9:35 AM–10:50 AM', 'ED 2275', 'Richard Carter', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to prepare future teachers with the knowledge required to integrate assistive technology into curricula for students with mild to moderate disabilities.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 441', 'TRANSITION ACROSS THE LIFESPAN', '13797', 'Class Status', NULL, 'WB WEB', 'Teresa Grossi', 14, NULL, 'Lecture', '2–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to give prospective teachers information and skills necessary to effectively teach students with disabilities at the high school level. An overview of characteristics of secondary students with mild disabilities, school programs, transition from school life to adult life, curriculum issues, and strategies of effective instruction for students with disabilities will be covered.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 480', 'STUDENT TEACHING IN SPECIAL EDUCATION', '12497', 'Class Status', NULL, 'WB WEB', 'Tyna Hunnicutt, Samantha Walterman', 8, NULL, 'Practicum', '7', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Full time supervised student teaching for a minimum of 8 weeks. The experience is directed by a qualified supervising teacher and has university-provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 488', 'SUPERVISED TEACHING IN SPECIAL EDUCATION', '1525', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 14, NULL, 'Lecture', '10', NULL, ARRAY[]::TEXT[], 'Provides students an opportunity to teach exceptional children under the supervision of a licensed special education teacher and a University special education supervisor.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 500', 'TOPICAL WORKSHOP IN SPECIAL EDUCATION', '5301', 'Class Status', NULL, 'WB WEB', 'Alisa Lowrey', 6, NULL, 'Lecture', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Intensive study of such selected topics as language development for exceptional children, the disadvantaged child, and behavior modification for exceptional children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 505', 'INTROD SP ED FOR GRAD STUDENTS', '11447', 'Class Status', NULL, 'WB WEB', 'Theresa Ochoa', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-K 535', 'ASSESSMENT THAT SUPPORTS INSTRUCTION IN SPECIAL EDUCATION', '11137', 'Class Status', NULL, 'WB WEB', 'Aerin Welch', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Emphasizes data-driven instructional decision-making that addresses academic and adaptive challenges of students with mild to moderate disabilities. Provides an overview of critical measurement concepts and types of assessments. Instruction is anchored in case studies and real-world application.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 541', 'TRANSITION ACROSS LIFE SPAN', '13798', 'Class Status', NULL, 'WB WEB', 'Teresa Grossi', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'In this course, issues and strategies related to the array of transitions students with disabilities need to make as they progress from pre-school to public school and on to adult life are discussed. The course covers laws, policies, and guidelines governing service provision across age groups and levels of instruction, and it addresses strategies for program planning, interagency cooperation and collaboration, and resource utilization.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 553', 'CLASSROOM MANAGEMENT AND BEHAVIOR SUPPORT', '34641', 'Class Status', NULL, 'OL ONLINE', 'Lynn Reed', 10, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Surveys principles of behavior management as they pertain to educational environments. Students will learn how to define, observe, measure, record, and change academic and social behavior.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 570', 'INTENSIVE READING INTERVENTIONS AND SUPPORTS FOR STUDENTS WITH DYSLEXIA', '32598', 'Class Status', NULL, 'WB WEB', 'Kelly Grillo', 1, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines methods and practices for designing and delivering intensive, evidence-based interventions (i.e., specially designed instruction) in reading for students with dyslexia. Covers explicit, direct instruction that is systematic, sequential, cumulative, diagnostic, and multisensory. Examines how to intensify and individualize instruction and provide supports to meet students'' unique needs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 570', 'INTENSIVE READING INTERVENTIONS AND SUPPORTS FOR STUDENTS WITH DYSLEXIA', '29959', 'Closed', NULL, 'WB WEB', 'Kelly Grillo', 0, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines methods and practices for designing and delivering intensive, evidence-based interventions (i.e., specially designed instruction) in reading for students with dyslexia. Covers explicit, direct instruction that is systematic, sequential, cumulative, diagnostic, and multisensory. Examines how to intensify and individualize instruction and provide supports to meet students'' unique needs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 590', 'INDEPENDENT STUDY OR RESEARCH IN SPECIAL EDUCATION', '15222', 'Class Status', NULL, NULL, 'Sarah Hurwitz', 2, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Special Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, K590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 590', 'INDEPENDENT STUDY OR RESEARCH IN SPECIAL EDUCATION', '7654', 'Class Status', NULL, NULL, 'Derek Nord', 5, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Special Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, K590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 601', 'INTRODUCTION TO SPECIAL EDUCATION SCHOLARSHIP', '5564', 'Class Status', 'F Friday 12:45 PM–1:35 PM', 'ED 1235', 'Sarah Hurwitz', 7, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This seminar provides students familiarity with the professional field of special education by introducing them to relevant conferences, journals, book publishers within the field of special education. Students read conference papers, articles and/or book chapters written by our faculty; and students discuss these readings with the authors. Activities might include advanced doctoral students presenting papers and/or discussions on the occupational socialization of SPED doctoral students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 631', 'INTRODUCTION TO AUTISM', '6245', 'Class Status', 'Thirteen Week', 'WB WEB', 'Sarah Hurwitz', 8, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Provides a broad but substantive survey of research, issues, and trends; promotes critical examination of what is known and is unknown about autism spectrum disorders (ASD); and examines perspectives of individuals with ASD and their families.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 643', 'DISABILITY RIGHTS, POLICY, AND SERVICES', '12721', 'Class Status', NULL, 'WB WEB', 'Derek Nord, John Andresen', 5, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The class will examine contemporary research, evidence-based practices, and policy issues, related to public systems that people with disabilities often engage. With a focus on rights, policy and services, issues of equity, exclusion/inclusion, best practices, and social justice from historical and current day perspectives will be explored.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 780', 'SEMINAR IN SPECIAL EDUCATION', '11446', 'Class Status', 'M Monday 2:20 PM–4:50 PM', 'ED 1235', 'Richard Carter', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intensive advanced study of selected problems in the field.', ARRAY[]::TEXT[], NULL),
    ('EDUC-K 785', 'INTERNSHIP IN SPECIAL EDUCATION', '1526', 'Class Status', NULL, NULL, 'Sarah Hurwitz', 7, NULL, 'Practicum', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-K 795', 'DISSERTATION PROPOSAL PREP', '1527', 'Class Status', NULL, NULL, 'Sarah Hurwitz', 9, NULL, 'Lecture', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-K 799', 'DOCTORAL THESIS IN SPECIAL EDUCATION', '1528', 'Class Status', NULL, NULL, 'Sarah Hurwitz', 10, NULL, 'Independent Study', '1–15', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-L 239', 'LANGUAGE AND LEARNING', '8491', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 2275', 'Melody Lynch-Kimery', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examines the role of language in creating, maintaining, and changing educational practices. Topics include bilingualism, dialects, heritage languages, language-in-education policy, language revitalization, and first and second language learning. Other topics include basic linguistic principles that are useful for pedagogy in both formal and informal contexts.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-L 407', 'LANG EDUC ISSUES FOR ENG TCHRS', '6047', 'Class Status', NULL, 'WB WEB', 'Mary Beth Hines', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Study of growth in language as a developmental process and how social, cultural, and economic environments are intrinsic parts of language learning. Explores the close relationship between how home language, dialect, and a second language is developed. Addresses how speaking, listening, writing, reading, and observing are interrelated.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 408', 'TEACHING YOUNG ADULT LITERATURE IN A DIVERSE SOCIETY', '3747', 'Closed', NULL, 'WB WEB', 'Angela Cannon', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores the possibilities of reading literature written for, by, and about young adults in the middle and secondary classroom. We will work on engaging diverse young adults so that they become lifelong readers and responsible citizens; creating curricula and instructional activities that enable students to read the word and the world; and connecting with struggling readers while challenging proficient readers.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 442', 'TEACHING ENGLISH LANGUAGE LEARNERS: BILINGUAL AND ENGLISH AS A NEW LANGUAGE INSTRUCTION', '9540', 'Class Status', 'MW Monday, Wednesday 7:05 PM–8:20 PM', 'ED 1201', 'Dee Degner', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces undergraduate students to the theory-based instructional methods and activities that are used in bilingual and English as a new language education program. In addition, they are introduced to second language development, theoretical applications, and the sociocultural issues involved in teaching language minority students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 451', 'LITERACY INSTRUCTION & ASSESSMENT 1', '32980', 'Class Status', 'W Wednesday 11:10 AM–1:40 PM', 'ED 0101', 'Daniel Castner', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to teach pre-service teachers fundamental principles and concepts of literacy development. The focus is on phonological awareness to reading and methods of structured systematic instruction for phonemic awareness and phonics as well as developmentally appropriate activities for young children in preschool through second grade.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 451', 'LITERACY INSTRUCTION & ASSESSMENT 1', '33370', 'Class Status', 'Tu Tuesday 2:20 PM–4:50 PM', 'ED 3275', 'Jill Scott', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to teach pre-service teachers fundamental principles and concepts of literacy development. The focus is on phonological awareness to reading and methods of structured systematic instruction for phonemic awareness and phonics as well as developmentally appropriate activities for young children in preschool through second grade.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 451', 'LITERACY INSTRUCTION & ASSESSMENT 1', '33369', 'Closed', 'Th Thursday 11:10 AM–1:40 PM', 'ED 3025', 'Liesl Loudermilk', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to teach pre-service teachers fundamental principles and concepts of literacy development. The focus is on phonological awareness to reading and methods of structured systematic instruction for phonemic awareness and phonics as well as developmentally appropriate activities for young children in preschool through second grade.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 451', 'LITERACY INSTRUCTION & ASSESSMENT 1', '33371', 'Closed', 'M Monday 5:30 PM–8:00 PM', 'ED 3275', 'Kimberly Beathea', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to teach pre-service teachers fundamental principles and concepts of literacy development. The focus is on phonological awareness to reading and methods of structured systematic instruction for phonemic awareness and phonics as well as developmentally appropriate activities for young children in preschool through second grade.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 451', 'LITERACY INSTRUCTION & ASSESSMENT 1', '33373', 'Closed', 'W Wednesday 5:30 PM–8:00 PM', 'ED 3025', 'Cindy Stark', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to teach pre-service teachers fundamental principles and concepts of literacy development. The focus is on phonological awareness to reading and methods of structured systematic instruction for phonemic awareness and phonics as well as developmentally appropriate activities for young children in preschool through second grade.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 452', 'METHODS OF LITERACY INSTRUCTION & ASSESSMENT II', '33385', 'Class Status', 'M Monday 11:10 AM–1:40 PM', 'ED 3115', 'Liesl Loudermilk', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on fluency and vocabulary in reading and writing development, emphasizing methods for teaching fluency and vocabulary using explicit and systematic instruction in grades 3-6 for word study (morphology), grammar (syntax), and spelling(orthography). This course equips preservice teachers with culturally responsive methods for teaching multilingual learners and biliteracies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 452', 'METHODS OF LITERACY INSTRUCTION & ASSESSMENT II', '33408', 'Closed', 'W Wednesday 2:20 PM–4:50 PM', 'ED 3025', 'Yaitza Rodriguez', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on fluency and vocabulary in reading and writing development, emphasizing methods for teaching fluency and vocabulary using explicit and systematic instruction in grades 3-6 for word study (morphology), grammar (syntax), and spelling(orthography). This course equips preservice teachers with culturally responsive methods for teaching multilingual learners and biliteracies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33070', 'Class Status', 'Tu Tuesday 8:00 AM–10:30 AM', 'ED 1004', 'Lisa Roberts', 14, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33386', 'Class Status', 'Th Thursday 5:30 PM–8:00 PM', 'ED 3025', 'Steven Marshall', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33389', 'Class Status', 'W Wednesday 11:10 AM–1:40 PM', 'ED 3025', 'Amy Waechter-Versaw', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33397', 'Class Status', 'M Monday 2:20 PM–4:50 PM', 'ED 2025', 'Kari Esarey', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33387', 'Closed', 'M Monday 2:20 PM–4:50 PM', 'ED 3275', 'Cindy Stark', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 453', 'METHODS OF LITERACY INSTRUCT & ASSESS III', '33388', 'Closed', 'Tu Tuesday 11:10 AM–1:40 PM', 'ED 3025', 'Liesl Loudermilk', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on explicit and systematic instruction of reading comprehension and writing curriculum to support critical thinking in K-6 interdisciplinary content areas. Students teach effective comprehension strategies across a range of fiction and nonfiction genres, according to their different purposes, contexts, and text features for reading and writing text.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33363', 'Class Status', NULL, 'WB WEB', 'Jill Scott', 4, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33390', 'Class Status', NULL, 'WB WEB', 'Suzanne Thomson', 2, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33395', 'Class Status', NULL, 'WB WEB', 'Amy Waechter-Versaw', 1, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33396', 'Class Status', NULL, 'WB WEB', 'Suzanne Thomson', 4, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33392', 'Closed', NULL, 'WB WEB', 'Cindy Stark', 0, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 454', 'LITERACY FOUNDATIONS: APPLICATION & ASSESSMENT', '33394', 'Closed', NULL, 'WB WEB', 'Kimberly Beathea', 0, NULL, 'Methods Course', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course focuses on applying in-depth knowledge of systematic and explicit instruction of oral language, phonemic awareness, phonics, fluency, vocabulary, and comprehension in classroom situations. It addresses the use of formal and informal assessment procedures used to design and evaluate robust reading instruction and intervention for children in P-6 grades.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 490', 'RESEARCH IN LANGUAGE EDUCATION', '5497', 'Class Status', 'Tu Tuesday 10:25 AM–12:25 PM', 'CU 302', 'Molly Burke', 6, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'Individual research. Variable title course. May be repeated for credit.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 500', 'INSTRUCTIONAL ISSUES IN LITERACY, CULTURE, AND LANGUAGE EDUCATION', '1529', 'Class Status', NULL, 'WB WEB', 'Samira Al Hosni', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This required master''s degree course provides an overview of current theory, research, and practice issues related to language, culture, and literacy education. The course takes up current scholarship that explores social, cultural, and political aspects of 21st century language and literacy practices in the classroom, community, and in the culture.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 517', 'ADVANCED STUDY OF CONTENT READING AND ADOLESCENT LITERACY', '3291', 'Class Status', 'M Monday 5:30 PM–8:00 PM', 'ED 2275', 'Sandra Slaughter', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examines approaches for improving adolescent/adult literacy when reading the specialized materials of various content areas. Special focus upon the literacy process, dealing with a wide range of student literacy abilities, identifying and modifying materials to support literacy development, and using reading, writing, and thinking activities in instruction.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 517', 'ADVANCED STUDY OF CONTENT READING AND ADOLESCENT LITERACY', '14828', 'Class Status', NULL, 'WB WEB', 'Erin McNeill', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examines approaches for improving adolescent/adult literacy when reading the specialized materials of various content areas. Special focus upon the literacy process, dealing with a wide range of student literacy abilities, identifying and modifying materials to support literacy development, and using reading, writing, and thinking activities in instruction.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 520', 'ADVANCED STUDY IN FOREIGN LANGUAGE TEACHING', '1531', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'ED 1250', 'Samira Al Hosni', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Principles, practices, problems, and current research pertaining to the teaching of a particular modern language in the secondary school. Emphasis on teaching the advanced levels. Separate sections as needed for teachers of French, German, Russian, and Spanish.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 539', 'LANGUAGE FOUNDATIONS FOR ESL/EFL TEACHERS', '8397', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 2275', 'Melody Lynch-Kimery', 10, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focus on identification of systematic aspects of English that could challenge English Language Learners at different proficiency levels of language acquisition. Students engage in the discussion and development of modification approaches that address language needs in content classes with attention to socio-cultural aspects of language use and language learning experiences of diverse students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 540', 'ESL/EFL INSTRUCTION AND ASSESSMENT APPROACHES', '8398', 'Class Status', NULL, 'WB WEB', 'Beth Samuelson', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The course provides an overview of various approaches to instruction and assessment that incorporate the current thinking in the field. Includes discussion of content-based models of language instruction and standardized, alternative, and authentic forms of assessment.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-L 599', 'MASTERS THESIS IN LITERACY, CULTURE AND LANGUAGE EDUCATION', '13786', 'Class Status', 'M Monday 5:30 PM–8:00 PM', 'ED 2280', 'Serafin Coronel-Molina', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To be used as the master''s thesis in language education or the early inquiry experience as part of the doctoral program. The thesis or inquiry experience may be an organized study or a systematic and comprehensive analysis of theory and practice in a specific area.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 600', 'ISSUES IN LITERACY, CULTURE AND LANGUAGE EDUCATION', '9122', 'Class Status', 'Th Thursday 5:30 PM–8:00 PM', 'ED 1225', 'Marcus Croom', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Explores research and arguments related to current issues in first and second language education with focus upon issues in learning, instruction, assessment, and policy. Studies and interrelates research done in the areas of reading, English education, and second language education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 600', 'ISSUES IN LITERACY, CULTURE AND LANGUAGE EDUCATION', '7508', 'Class Status', NULL, 'WB WEB', 'Sharon Daley', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Explores research and arguments related to current issues in first and second language education with focus upon issues in learning, instruction, assessment, and policy. Studies and interrelates research done in the areas of reading, English education, and second language education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 600', 'ISSUES IN LITERACY, CULTURE AND LANGUAGE EDUCATION', '8274', 'Class Status', NULL, 'WB WEB', 'Vesna Dimitrieska', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Explores research and arguments related to current issues in first and second language education with focus upon issues in learning, instruction, assessment, and policy. Studies and interrelates research done in the areas of reading, English education, and second language education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 602', 'THEORETICAL ISSUES IN THE STUDY OF LANGUAGE AND LITERACIES PART II', '30118', 'Class Status', NULL, 'WB WEB', 'James Damico', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Situates theoretical perspectives in language and literacy research and classroom practice. Builds on perspectives introduced in L601 to focus on students'' identified areas of expertise and apply deeper theoretical understandings and current research to issues of practice in a diverse society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 602', 'THEORETICAL ISSUES IN THE STUDY OF LANGUAGE AND LITERACIES PART II', '30119', 'Class Status', NULL, 'WB WEB', 'Karen Wohlwend', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Situates theoretical perspectives in language and literacy research and classroom practice. Builds on perspectives introduced in L601 to focus on students'' identified areas of expertise and apply deeper theoretical understandings and current research to issues of practice in a diverse society.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 603', 'ISSUES IN LITERACY, CULTURE, AND LANGUAGE EDUCATION PART II', '34595', 'Closed', NULL, 'WB WEB', 'James Damico', 0, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Analyze and develop responses to a specific issue of practice in a major field of study within Literacy, Culture, and Language Education. L603 builds on exploration of issues in L600 survey course by targeting a specific issue relevant to the student''s context and research goals.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 630', 'TOPICS IN LITERACY, CULTURE AND LANGUAGE EDUCATION', '32450', 'Closed', 'W Wednesday 5:30 PM–8:00 PM', 'ED 1235', 'Beth Samuelson', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Study of special topics in the field of language education. Emphasis on research applications to the improvement of practice.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 650', 'INTERNSHIP IN LITERACY, CULTURE, LANGUAGE EDUCATION', '9025', 'Closed', NULL, NULL, 'Beth Samuelson', 0, NULL, 'Internship', '3', NULL, ARRAY[]::TEXT[], 'The course will provide opportunities to consider how research and teaching can be taken up from different perspectives within literacy, culture, and language education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 690', 'READINGS IN LITERACY, CULTURE, AND LANGUAGE EDUCATION', '9290', 'Class Status', NULL, NULL, 'Beth Samuelson', 1, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-L 690', 'READINGS IN LITERACY, CULTURE, AND LANGUAGE EDUCATION', '11609', 'Closed', NULL, 'WB WEB', 'Sharon Daley', 0, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-L 699', 'DOCTORAL EARLY INQUIRY IN LITERACY, CULTURE, AND LANGUAGE EDUCATION', '12608', 'Class Status', NULL, 'WB WEB', 'Sharon Daley', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides a collaborative space to support graduate students who are learning to design, conduct, and write up research by providing structured opportunities to develop student-led research. Includes methods of data collection and data analysis of language and literacy; emphasizes primarily qualitative research in Literacy, Culture, and Language Education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 699', 'DOCTORAL EARLY INQUIRY IN LITERACY, CULTURE, AND LANGUAGE EDUCATION', '12609', 'Class Status', NULL, 'WB WEB', 'Mary Beth Hines', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides a collaborative space to support graduate students who are learning to design, conduct, and write up research by providing structured opportunities to develop student-led research. Includes methods of data collection and data analysis of language and literacy; emphasizes primarily qualitative research in Literacy, Culture, and Language Education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 700', 'SEMINAR-LITERACY, CULTURE AND LANGUAGE EDUCATION RESEARCH', '9698', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 1235', 'Serafin Coronel-Molina', 1, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An in-depth treatment of various issues and trends in the design and status of language education research. Students will evaluate and critique extant research, outline a detailed program of language education research for themselves, and conduct initial studies related to this research program.', ARRAY[]::TEXT[], NULL),
    ('EDUC-L 700', 'SEMINAR-LITERACY, CULTURE AND LANGUAGE EDUCATION RESEARCH', '8568', 'Class Status', 'Thirteen Week', 'WB WEB', 'Karen Wohlwend', 7, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An in-depth treatment of various issues and trends in the design and status of language education research. Students will evaluate and critique extant research, outline a detailed program of language education research for themselves, and conduct initial studies related to this research program.', ARRAY[]::TEXT[], NULL),
