    ('EDUC-M 101', 'LABORATORY/FIELD EXPERIENCE', '1535', 'Closed', NULL, 'WB WEB', 'Matthew Nussbaum', 0, NULL, 'Laboratory', '0', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Laboratory or field experience for freshman.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 101', 'LABORATORY/FIELD EXPERIENCE', '12639', 'Closed', NULL, 'WB WEB', 'Matthew Nussbaum', 0, NULL, 'Laboratory', '0', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Laboratory or field experience for freshman.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 130', 'CHILD ART: UNDERSTANDING CHILDREN''S ARTISTIC WORLDS', '11524', 'Closed', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 3125', 'Susan Livingston', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to the nature, meanings and development of children''s visual/artistic expressions and aesthetic responses, from childhood through adolescence, across culture and time. Students will analyze children''s artworks and reactions to images through readings, case studies, and field experiences, and consider implications for promoting artistic and aesthetic growth.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 135', 'INDIVIDUALIZED INSTRUCTION IN ART', '9657', 'Class Status', 'Th Thursday 5:30 PM–7:30 PM', 'WB WEB', 'Cheryl Maxwell', 4, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A studio art course for non-art majors, taught in an online format. Students select topics and media from a range of prepared options. Past experiences in art making are not required; work is assessed based on meeting personal and course objectives rather than talent.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 135', 'INDIVIDUALIZED INSTRUCTION IN ART', '9658', 'Class Status', 'Th Thursday 5:30 PM–7:30 PM', 'WB WEB', 'Cheryl Maxwell', 8, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A studio art course for non-art majors, taught in an online format. Students select topics and media from a range of prepared options. Past experiences in art making are not required; work is assessed based on meeting personal and course objectives rather than talent.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 135', 'INDIVIDUALIZED INSTRUCTION IN ART', '11535', 'Class Status', 'M Monday 5:30 PM–7:30 PM', 'WB WEB', 'Cheryl Maxwell', 3, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A studio art course for non-art majors, taught in an online format. Students select topics and media from a range of prepared options. Past experiences in art making are not required; work is assessed based on meeting personal and course objectives rather than talent.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 135', 'INDIVIDUALIZED INSTRUCTION IN ART', '11536', 'Class Status', 'W Wednesday 5:30 PM–7:30 PM', 'WB WEB', 'Cheryl Maxwell', 8, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A studio art course for non-art majors, taught in an online format. Students select topics and media from a range of prepared options. Past experiences in art making are not required; work is assessed based on meeting personal and course objectives rather than talent.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 200', 'ARTIFACTS, MUSEUMS AND EVERYDAY LIFE', '4308', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 3125', 'Esra Ibil', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'In a combination of museum visits and classroom exercises, develop museum-going skills by exploring a range of artifacts reflecting varied media, world cultures, and inquiry disciplines. Discussion, guided conversational techniques, readings and analytical writing assignments draw on "learning from objects" literature, art history, criticism, and museum education materials.', ARRAY['IUB GenEd A&H credit'], NULL),
    ('EDUC-M 200', 'ARTIFACTS, MUSEUMS AND EVERYDAY LIFE', '5489', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 3125', 'Jaeun Won', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'In a combination of museum visits and classroom exercises, develop museum-going skills by exploring a range of artifacts reflecting varied media, world cultures, and inquiry disciplines. Discussion, guided conversational techniques, readings and analytical writing assignments draw on "learning from objects" literature, art history, criticism, and museum education materials.', ARRAY['IUB GenEd A&H credit'], NULL),
