    ('EDUC-M 201', 'LABORATORY/FIELD EXPERIENCE', '11183', 'Closed', 'W Wednesday 8:00 AM–11:45 AM', 'HD TBA', 'Kristine Stewart', 0, NULL, 'Laboratory', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Laboratory or field experience for sophomores.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 201', 'LABORATORY/FIELD EXPERIENCE', '12572', 'Closed', 'Tu Tuesday 8:00 AM–11:45 AM', 'HD TBA', 'Shelby Newland', 0, NULL, 'Laboratory', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Laboratory or field experience for sophomores.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 201', 'LABORATORY/FIELD EXPERIENCE', '14196', 'Closed', 'W Wednesday 8:00 AM–11:45 AM', 'HD TBA', 'Sharon Daley', 0, NULL, 'Laboratory', '2', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Laboratory or field experience for sophomores.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-M 202', 'JOB SEARCH STRATEGIES FOR EDUCATORS', '1537', 'Class Status', NULL, 'WB WEB', 'Shawn Wilson', 7, NULL, 'Lecture', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'To provide students entering the educational job market with the employment skills needed to aid them in their job search, materials processing, interview skill development, and licensure procedures. For many students this course serves as the capstone experience prior to or during student teaching.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 222', 'TRAUMA-INFORMED ARTS-BASED SCHOOL AND COMMUNITY ART EDUCATION', '32570', 'Class Status', 'Thirteen Week', 'WB WEB', 'Marjorie Manifold, Emily Wittenstein', 3, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course presents arts-based approaches to working with youth and adults and school or community contexts in response to traumatic events. Strategies are appropriate to teachers in k-16 schools and community programs. Course materials are drawn from museum studies, arts education, art therapy, neuroaesthetics, and social emotional learning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 235', 'ART, INTERDISCIPLINARITY, AND EDUCATION', '12679', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'ED 3115', 'Gustave Weltsek', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An introduction to artists and artistic practices that explore connections between art and language arts, mathematics, science, social studies, and other non-art disciplines. Emphasis on engaging with, analyzing and responding to artworks, for general knowledge or as a basis for arts integrated curricula. No background in art or education required.', ARRAY['IUB GenEd A&H credit'], NULL),
