    ('EDUC-M 302', 'MATHEMATICS THROUGHOUT THE SECONDARY CURRICULUM', '14251', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 203', 'Lori Burch', 5, NULL, 'Lecture', '1–3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students engage in making connections between the mathematical content of certain required mathematics courses and the teaching and learning of secondary school mathematics. Students analyze important "big ideas" in mathematics. Additionally, students prepare and collect lesson plans for use during student teaching and beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 302', 'MATHEMATICS THROUGHOUT THE SECONDARY CURRICULUM', '15088', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 2271', 'Amy Hackenberg', 4, NULL, 'Lecture', '1–3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students engage in making connections between the mathematical content of certain required mathematics courses and the teaching and learning of secondary school mathematics. Students analyze important "big ideas" in mathematics. Additionally, students prepare and collect lesson plans for use during student teaching and beyond.', ARRAY[]::TEXT[], NULL),
