    ('EDUC-M 330', 'DESIGNING VISUAL LEARNING EXPERIENCES FOR CHILDREN', '1546', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'ED 3125', 'Roy Reynolds', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An introduction to fundamentals of designing and facilitating children''s visual art learning experiences in schools, community centers or museums. Emphasis on pedagogy in the context of practice and field experiences with children. Required for art education majors. Non-art education majors welcome with instructor permission.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 330', 'DESIGNING VISUAL LEARNING EXPERIENCES FOR CHILDREN', '11187', 'Class Status', 'TuTh Tuesday, Thursday 5:30 PM–6:45 PM', 'ED 3125', 'Roy Reynolds', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An introduction to fundamentals of designing and facilitating children''s visual art learning experiences in schools, community centers or museums. Emphasis on pedagogy in the context of practice and field experiences with children. Required for art education majors. Non-art education majors welcome with instructor permission.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 333', 'ART EXPERIENCES FOR THE ELEMENTARY TEACHER', '1547', 'Closed', 'W Wednesday 2:20 PM–3:55 PM', 'ED 3115', 'Elizabeth Jenkins', 0, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Development of skills in viewing and discussing art, guidance in selecting and organizing visuals and media for art instruction in the elementary classroom.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 333', 'ART EXPERIENCES FOR THE ELEMENTARY TEACHER', '14758', 'Closed', NULL, 'WB WEB', 'Elizabeth Jenkins', 0, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Development of skills in viewing and discussing art, guidance in selecting and organizing visuals and media for art instruction in the elementary classroom.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 334', 'DRAMA IN EDUCATION', '8897', 'Class Status', 'Tu Tuesday 9:35 AM–11:10 AM', 'ED 3115', 'Bo Yang', 4, NULL, 'Methods Course', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to introduce students to a wide variety of places, spaces and ways that drama, as a critical social and cultural experience, may be thought about and used with youth. Students will play with multiple drama and theatre strategies with an eye on ways in which individual these may inform student social and academic growth. It is intended that upon completion of this course students will feel comfortable infusing drama throughout their classroom and curriculum. Student are also expected to be able to articulate how their pedagogy and praxis may be informed through drama. - support the novice and inspire the veteran dramatic arts educator - provide direction for learning design, assessment, and evaluation - set out the philosophical and pedagogical foundations for dramatic arts learning - articulate a palette of possibilities for learning design', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 334', 'DRAMA IN EDUCATION', '8898', 'Class Status', 'W Wednesday 11:10 AM–12:45 PM', 'ED 3115', 'Bo Yang', 8, NULL, 'Methods Course', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is designed to introduce students to a wide variety of places, spaces and ways that drama, as a critical social and cultural experience, may be thought about and used with youth. Students will play with multiple drama and theatre strategies with an eye on ways in which individual these may inform student social and academic growth. It is intended that upon completion of this course students will feel comfortable infusing drama throughout their classroom and curriculum. Student are also expected to be able to articulate how their pedagogy and praxis may be informed through drama. - support the novice and inspire the veteran dramatic arts educator - provide direction for learning design, assessment, and evaluation - set out the philosophical and pedagogical foundations for dramatic arts learning - articulate a palette of possibilities for learning design', ARRAY[]::TEXT[], NULL),
