    ('EDUC-M 403', 'LABORATORY/FIELD EXPERIENCES:', '1552', 'Class Status', NULL, NULL, 'Tyna Hunnicutt', 6, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Laboratory or field experiences at the high school level.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 403', 'LABORATORY/FIELD EXPERIENCES:', '1553', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'ED 1250', 'Samira Al Hosni', 0, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Laboratory or field experiences at the high school level.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 416', 'INQUIRY INTO SECONDARY ENGLISH METHODS: HIGH SCHOOL', '5147', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 1004', 'Rhonda Hylton', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Study of current trends, issues, theory and research in teaching and learning English/Language Arts. Explores language, composition, literature, and media arts, developing multicultural curricula, and engaging students in meaningful inquiry facilitating student''s responsibility for themselves and their world.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 420', 'STUDENT TEACHING SEMINAR', '31069', 'Class Status', NULL, 'WB WEB', 'Sunil Sutherson', 51, NULL, 'Seminar', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This seminar will address several issues related to the process of becoming a teacher.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 420', 'STUDENT TEACHING SEMINAR', '31071', 'Class Status', NULL, 'WB WEB', 'Sunil Sutherson', 26, NULL, 'Seminar', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This seminar will address several issues related to the process of becoming a teacher.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 420', 'STUDENT TEACHING SEMINAR', '32403', 'Class Status', NULL, 'WB WEB', 'Sunil Sutherson', 53, NULL, 'Seminar', '1', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This seminar will address several issues related to the process of becoming a teacher.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 421', 'METHODS OF TEACHING JUNIOR/MIDDLE HIGH SCHOOL SOCIAL STUDIES', '3677', 'Closed', 'Th Thursday 2:20 PM–4:50 PM', 'ED 3275', 'Anneliese Paulson', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Develops concepts and theories from social science, humanities, and education into practices of successful social studies instruction. Integrates social issues and reflective thinking skills into the social studies curriculum. Emphasis on curriculum development skills and building a repertoire of teaching strategies appropriate for middle/secondary school learners.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 422', 'TEACHING MATHEMATICS IN THE SECONDARY SCHOOL', '3674', 'Class Status', 'MW Monday, Wednesday 4:05 PM–5:20 PM', 'ED 3017', 'Lori Burch', 12, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Development of knowledge and skills related to analysis and design of mathematics instruction in secondary school mathematics, with attention to selection of appropriate mathematical tasks and tools and the development of classroom discourse communities.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 424', 'STUDENT TEACHING: K-PRIMARY', '6663', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 1, NULL, 'Practicum', '10', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching for a full semester divided equally between a kindergarten and primary grade in a school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 424', 'STUDENT TEACHING: K-PRIMARY', '7499', 'Class Status', NULL, NULL, 'Laura Stachowski', 10, NULL, 'Practicum', '10', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching for a full semester divided equally between a kindergarten and primary grade in a school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 425', 'STUDENT TEACH: ELEMENTARY', '1555', 'Class Status', NULL, NULL, 'Laura Stachowski', 88, NULL, 'Practicum', '8–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching in grades 1-6 for a minimum of ten weeks in an elementary school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 425', 'STUDENT TEACH: ELEMENTARY', '8504', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 62, NULL, 'Practicum', '8–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching in grades 1-6 for a minimum of ten weeks in an elementary school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 427', 'SPECIAL EDUCATION STUDENT TEACHING SEMINAR', '12496', 'Class Status', NULL, 'WB WEB', 'Richard Carter', 8, NULL, 'Seminar', '2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This online seminar has been developed for candidates in the Teaching All Learner''s (TAL) program as they bridge knowledge of theory with practice in student teaching while in special education placements. M427 is a complementary seminar to M420 student teaching seminar with the Office of Clinical Practices. TAL candidates will be in M420 during their general elementary education placement and in M427 during their special education placement. The M427 seminar will be structured for fall and spring semesters and align with candidate'' student teaching in special education in the local area (within a 60 mile area around Bloomington). The content of M427 will be closely aligned with the current M420 student teaching seminar when candidates are completing their teacher performance assessment (edTPA). TAL candidates will have a choice to complete the edTPA during the special education placement or during the general education placement. M427 will also integrate content standards from Council for Exceptional Children (CEC Standards, 2012) for collaboration. Collaboration standards will be addressed in each seminar (M420 and M427). The content for M427 will vary depending on whether candidates are completing the Special Education edTPA in this semester. For this reason M427 will offer two tracks candidates must follow to successfully complete the seminar M427 edTPA Track or M427 non-edTPA Track. The edTPA must be successfully completed in either M427 or M420.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 445', 'METHODS OF TEACHING FOREIGN LANGUAGE', '1558', 'Closed', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'ED 1250', 'Samira Al Hosni', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Development and practice of skills and techniques of teaching foreign languages, selection of content and materials, and evaluation of students and teacher performance. Micro-teaching laboratory included. This course should be taken during the semester immediately preceding student teaching.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 446', 'METHODS OF TEACHING SENIOR/JUNIOR HIGH/MIDDLE SCHOOL SCIENCE', '3679', 'Class Status', 'M Monday 3:10 PM–5:10 PM', 'ED 3105 ED 3105', 'Adam Maltese, Gholamreza Shamsi Pour Siahmazgi', 15, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Designed for students who plan to teach Biology, Chemistry, Earth Science, General Science or Physics in Junior High/Middle School/Secondary school.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 469', 'CONTENT AREA LITERACY', '5478', 'Class Status', 'M Monday 5:30 PM–8:00 PM', 'ED 2275', 'Sandra Slaughter', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focuses on middle, junior, senior high school. Curriculum, methods and materials for teaching students to read and learn more effectively in all content areas.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 470', 'PRACTICUM', '1559', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 9, NULL, 'Practicum', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Teaching or experience under the direction of an identified supervising teacher and with University provioded supervision in the endorsement or minor area and at the level appropriate to the area and in an accredited school within the State of Indiana unless the integral program includes experience in an approved and accredited out-of-state site. The practicum may be full or part-time but in every instance the amount of credit granted will be commensurate with the amount of time spent in the instructional setting.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 470', 'PRACTICUM', '1561', 'Class Status', NULL, NULL, 'Laura Stachowski', 50, NULL, 'Practicum', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Teaching or experience under the direction of an identified supervising teacher and with University provioded supervision in the endorsement or minor area and at the level appropriate to the area and in an accredited school within the State of Indiana unless the integral program includes experience in an approved and accredited out-of-state site. The practicum may be full or part-time but in every instance the amount of credit granted will be commensurate with the amount of time spent in the instructional setting.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 470', 'PRACTICUM', '5405', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 14, NULL, 'Practicum', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Teaching or experience under the direction of an identified supervising teacher and with University provioded supervision in the endorsement or minor area and at the level appropriate to the area and in an accredited school within the State of Indiana unless the integral program includes experience in an approved and accredited out-of-state site. The practicum may be full or part-time but in every instance the amount of credit granted will be commensurate with the amount of time spent in the instructional setting.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 470', 'PRACTICUM', '11157', 'Class Status', NULL, 'WB WEB', 'Anjali Gottipaty', 10, NULL, 'Practicum', '6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Teaching or experience under the direction of an identified supervising teacher and with University provioded supervision in the endorsement or minor area and at the level appropriate to the area and in an accredited school within the State of Indiana unless the integral program includes experience in an approved and accredited out-of-state site. The practicum may be full or part-time but in every instance the amount of credit granted will be commensurate with the amount of time spent in the instructional setting.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 480', 'STUDENT TEACHING: SECONDARY', '1563', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 111, NULL, 'Practicum', '10–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching for a minimum of ten weeks in either a junior high or middle school or high school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 480', 'STUDENT TEACHING: SECONDARY', '1564', 'Class Status', NULL, NULL, 'Laura Stachowski', 99, NULL, 'Practicum', '10–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching for a minimum of ten weeks in either a junior high or middle school or high school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 482', 'STUDENT TEACHING: ALL GRADES', '1565', 'Class Status', NULL, NULL, 'Tyna Hunnicutt, Samantha Walterman', 37, NULL, 'Practicum', '10–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching in the areas of Visual Arts, Music, Physical Education, Recreation, Special Education, or School Library/Media Services for a minimum of ten weeks at the elementary, junior high/middle school, and/or high school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 482', 'STUDENT TEACHING: ALL GRADES', '1566', 'Class Status', NULL, NULL, 'Laura Stachowski', 24, NULL, 'Practicum', '10–16', NULL, ARRAY[]::TEXT[], 'Full time supervised student teaching in the areas of Visual Arts, Music, Physical Education, Recreation, Special Education, or School Library/Media Services for a minimum of ten weeks at the elementary, junior high/middle school, and/or high school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 483', 'TEACHING SOCIAL STUDIES 5-12', '10476', 'Class Status', 'M Monday 11:10 AM–1:40 PM', 'ED 2101', 'Kathryn Engebretson', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Historical and contemporary roles of social studies will be explored with an emphasis on roles played by history, the social sciences and the humanities. Particular attention in given to development of skills essential to successful social studies instruction and a resource bank of instructional ideas.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 500', 'INTEGRATED PROFESSIONAL SEMINAR', '14885', 'Class Status', NULL, NULL, 'Lara Christoun', 5, NULL, 'Discussion', '1', NULL, ARRAY[]::TEXT[], 'This seminar if linked to courses and field experiences included in the Transition to Teaching (T2T) program. It will allow for collaboration among school-based mentors, university-based instructors and T2T candidates in offering academic content appropriate to the program. The seminar will provide a technology-rich and performance-based professional experience. This course has a fee attached.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 501', 'LABORATORY/FIELD EXPERIENCE', '3271', 'Class Status', 'MW Monday, Wednesday 5:30 PM–6:45 PM', 'ED 1250', 'Samira Al Hosni', 3, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A laboratory field experience in education for graduate students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 501', 'LABORATORY/FIELD EXPERIENCE', '1567', 'Class Status', NULL, NULL, 'Brent Gault', 18, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A laboratory field experience in education for graduate students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 501', 'LABORATORY/FIELD EXPERIENCE', '4565', 'Class Status', NULL, NULL, 'Brent Gault', 15, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A laboratory field experience in education for graduate students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 501', 'LABORATORY/FIELD EXPERIENCE', '11652', 'Class Status', 'Tu Tuesday 7:00 PM–8:00 PM', 'WB WEB', 'Alisa Lowrey', 6, NULL, 'Laboratory', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A laboratory field experience in education for graduate students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 502', 'MATHEMATICS THROUGHOUT THE SECONDARY CURRICULUM', '14252', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'WH 203', 'Lori Burch', 1, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students engage in making connections between the mathematical content of certain required mathematics courses and the teaching and learning of secondary school mathematics. Students analyze important "big ideas" in mathematics. Additionally, students prepare and collect lesson plans for use during student teaching and beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-M 502', 'MATHEMATICS THROUGHOUT THE SECONDARY CURRICULUM', '30213', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 2271', 'Amy Hackenberg', 4, NULL, 'Lecture', '3', 'WOODBURN HALL', ARRAY[]::TEXT[], 'Students engage in making connections between the mathematical content of certain required mathematics courses and the teaching and learning of secondary school mathematics. Students analyze important "big ideas" in mathematics. Additionally, students prepare and collect lesson plans for use during student teaching and beyond.', ARRAY[]::TEXT[], NULL),
