    ('EDUC-M 580', 'INTERNSHIP IN MUSIC', '1576', 'Class Status', NULL, NULL, 'Staff', 5, NULL, 'Practicum', '10', NULL, ARRAY[]::TEXT[], 'Full time supervised teaching in the area of Music for a minimum of ten weeks in an elementary or junior high/middle, or high school accredited by the State of Indiana or an equivalent approved school out-of-state. The experience is directed by a qualified supervising teacher and has university provided supervision.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 101', 'TEACHING AND LEARNING ELEMENTARY SCHOOL MATHEMATICS', '5346', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 1004', 'Selim Yavuz', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To develop an understanding of mathematics content and pedagogy relevant to being a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics learning and teaching and the Indiana Academic Standards. Pedagogical methods address reasoning about numbers, quantities, operations and algebra.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 101', 'TEACHING AND LEARNING ELEMENTARY SCHOOL MATHEMATICS', '5347', 'Closed', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 3017', 'Selim Yavuz', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To develop an understanding of mathematics content and pedagogy relevant to being a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics learning and teaching and the Indiana Academic Standards. Pedagogical methods address reasoning about numbers, quantities, operations and algebra.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 101', 'TEACHING AND LEARNING ELEMENTARY SCHOOL MATHEMATICS', '8896', 'Closed', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 3115', 'Hyunjeong Lee', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To develop an understanding of mathematics content and pedagogy relevant to being a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics learning and teaching and the Indiana Academic Standards. Pedagogical methods address reasoning about numbers, quantities, operations and algebra.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 101', 'TEACHING AND LEARNING ELEMENTARY SCHOOL MATHEMATICS', '8928', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 2275', 'Aaron Marsh', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To develop an understanding of mathematics content and pedagogy relevant to being a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics learning and teaching and the Indiana Academic Standards. Pedagogical methods address reasoning about numbers, quantities, operations and algebra.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 101', 'TEACHING AND LEARNING ELEMENTARY SCHOOL MATHEMATICS', '11756', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 2025', 'Bernard Smith', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'To develop an understanding of mathematics content and pedagogy relevant to being a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics learning and teaching and the Indiana Academic Standards. Pedagogical methods address reasoning about numbers, quantities, operations and algebra.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 103', 'TEACHING & LEARNING ELEMENTARY SCHOOL MATHEMATICS II', '37088', 'Closed', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 3017', 'Ladan Shojaei', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will help pre-service teachers develop an understanding of mathematics content and pedagogy relevant to be a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics teaching and learning and the State of Indiana Academic Standards.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 103', 'TEACHING & LEARNING ELEMENTARY SCHOOL MATHEMATICS II', '37089', 'Closed', 'MW Monday, Wednesday 8:00 AM–9:15 AM', 'ED 3017', 'Ladan Shojaei', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will help pre-service teachers develop an understanding of mathematics content and pedagogy relevant to be a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics teaching and learning and the State of Indiana Academic Standards.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 103', 'TEACHING & LEARNING ELEMENTARY SCHOOL MATHEMATICS II', '5533', 'Closed', 'Thirteen Week', 'WB WEB', 'Erik Jacobson', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will help pre-service teachers develop an understanding of mathematics content and pedagogy relevant to be a successful elementary school teacher. Focus is on content and methods that are consistent with recent recommendations about mathematics teaching and learning and the State of Indiana Academic Standards.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 310', 'MATHEMATICS IN THE MIDDLE SCHOOL', '11528', 'Class Status', 'MW Monday, Wednesday 4:05 PM–5:20 PM', 'ED 3017', 'Lori Burch', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Focuses on preparation for mathematics teaching in the middle school years by surveying content, methods, materials, and instructional issues.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 517', 'ADVANCED STUDY IN THE TEACHING OF SECONDARY SCHOOL MATHEMATICS', '3274', 'Class Status', 'MW Monday, Wednesday 4:05 PM–5:20 PM', 'ED 3017', 'Lori Burch', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Methods, materials, literature; laboratory practice with mathematics equipment; evaluation techniques; standards; and determination of essentials of content. Developing mathematics programs for specific school situations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 518', 'ADVANCED METHODS IN THE TEACHING OF MIDDLE/JUNIOR HIGH SCHOOL MATHEMATICS', '8183', 'Class Status', 'MW Monday, Wednesday 4:05 PM–5:20 PM', 'ED 3017', 'Lori Burch', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Combines theory of learning, curriculum development and research in the teaching of middle/junior high school mathematics with instructional strategies. Use made of laboratory and student experiences. Special attention given to establishing foundations on which to build instructional strategies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 590', 'INDEPENDENT STUDY OR RESEARCH IN MATHEMATICS EDUCATION', '1577', 'Class Status', NULL, NULL, 'Erik Jacobson', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Mathematics Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, this course should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 590', 'INDEPENDENT STUDY OR RESEARCH IN MATHEMATICS EDUCATION', '3498', 'Class Status', NULL, NULL, 'Erik Jacobson', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Mathematics Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, this course should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 610', 'INTERNSHIP IN MATHEMATICS EDUCATION', '1578', 'Class Status', NULL, NULL, 'Erik Jacobson', 6, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Under the direction of mathematics education faculty, experiences prescribed to coordinate professional practice with contemporary theory. The student''s professional goals will significantly influence the prescribed experiences.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 610', 'INTERNSHIP IN MATHEMATICS EDUCATION', '6247', 'Class Status', NULL, NULL, 'Erik Jacobson', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Under the direction of mathematics education faculty, experiences prescribed to coordinate professional practice with contemporary theory. The student''s professional goals will significantly influence the prescribed experiences.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 717', 'CONTEMPORARY ISSUES IN MATHEMATIC EDUCATION', '8638', 'Class Status', 'F Friday 2:20 PM–4:50 PM', 'ED 3017', 'Erik Jacobson', 18, NULL, 'Lecture', '1–3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An investigation of contemporary issues and problems in mathematics education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 720', 'RESEARCH ON ASSESSMENT IN MATHEMATICS EDUCATION', '32597', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 2280', 'Erik Jacobson', 11, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on assessment policies and practices in K-12 mathematics, addresses national/international mathematics education assessment data, and the limits of what can be learned from such data. We will examine large scale assessment data sets including NAEP, PISA, TIMSS, TALIS and engage in secondary analyses of these assessment data.', ARRAY[]::TEXT[], NULL),
    ('EDUC-N 731', 'EXPLORING RESEARCH BASED MATHEMATICS CURRICULUM', '32596', 'Class Status', NULL, 'WB WEB', 'Erik Tillema', 6, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course explores research on and the products of research-based curriculum in mathematics education. We will examine the most recent curriculum reform era, the 1990s, to see how it has shaped current curricular resources, including gaining an understanding of research on how curricular materials can impact classroom instruction.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 225', 'INTRODUCTION TO CHILD AND ADOLESCENT MENTAL HEALTH IN APPLIED SETTINGS', '12792', 'Closed', NULL, 'WB WEB', 'Hannah Pawlowski', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'There is a growing movement in the United States and in other countries to address childhood and adolescent mental health. This course will expose students to issues related to childhood and adolescent mental health including prevalence, diagnosis, school-based services, and culture and mental health.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 225', 'INTRODUCTION TO CHILD AND ADOLESCENT MENTAL HEALTH IN APPLIED SETTINGS', '12793', 'Closed', NULL, 'WB WEB', 'Hannah Pawlowski', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'There is a growing movement in the United States and in other countries to address childhood and adolescent mental health. This course will expose students to issues related to childhood and adolescent mental health including prevalence, diagnosis, school-based services, and culture and mental health.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 225', 'INTRODUCTION TO CHILD AND ADOLESCENT MENTAL HEALTH IN APPLIED SETTINGS', '12794', 'Closed', NULL, 'WB WEB', 'Danielle Gesell', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'There is a growing movement in the United States and in other countries to address childhood and adolescent mental health. This course will expose students to issues related to childhood and adolescent mental health including prevalence, diagnosis, school-based services, and culture and mental health.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 225', 'INTRODUCTION TO CHILD AND ADOLESCENT MENTAL HEALTH IN APPLIED SETTINGS', '14233', 'Closed', NULL, 'WB WEB', 'Danielle Gesell', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'There is a growing movement in the United States and in other countries to address childhood and adolescent mental health. This course will expose students to issues related to childhood and adolescent mental health including prevalence, diagnosis, school-based services, and culture and mental health.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 248', 'THE ELEMENTARY SCHOOL CHILD: PHYSICAL, EMOTIONAL, & SOCIAL DEVELOPMENT', '15046', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 2101', 'Nan Mu', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Child development in the school context. This course will provide an understanding of physical, emotional, and social development in a school marked by a diversity of cultural, social, and personal traits. Also, the role of the teacher in supporting positive development in students.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 248', 'THE ELEMENTARY SCHOOL CHILD: PHYSICAL, EMOTIONAL, & SOCIAL DEVELOPMENT', '4762', 'Closed', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 3017', 'Grace Mummert', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Child development in the school context. This course will provide an understanding of physical, emotional, and social development in a school marked by a diversity of cultural, social, and personal traits. Also, the role of the teacher in supporting positive development in students.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 248', 'THE ELEMENTARY SCHOOL CHILD: PHYSICAL, EMOTIONAL, & SOCIAL DEVELOPMENT', '11696', 'Closed', NULL, 'WB WEB', 'Yiming Han', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Child development in the school context. This course will provide an understanding of physical, emotional, and social development in a school marked by a diversity of cultural, social, and personal traits. Also, the role of the teacher in supporting positive development in students.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 248', 'THE ELEMENTARY SCHOOL CHILD: PHYSICAL, EMOTIONAL, & SOCIAL DEVELOPMENT', '12314', 'Closed', NULL, 'WB WEB', 'Yiming Han', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Child development in the school context. This course will provide an understanding of physical, emotional, and social development in a school marked by a diversity of cultural, social, and personal traits. Also, the role of the teacher in supporting positive development in students.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 248', 'THE ELEMENTARY SCHOOL CHILD: PHYSICAL, EMOTIONAL, & SOCIAL DEVELOPMENT', '12879', 'Closed', NULL, 'WB WEB', 'Grace Mummert', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Child development in the school context. This course will provide an understanding of physical, emotional, and social development in a school marked by a diversity of cultural, social, and personal traits. Also, the role of the teacher in supporting positive development in students.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 250', 'GENERAL EDUCATIONAL PSYCHOLOGY', '8863', 'Closed', NULL, 'WB WEB', 'Tiondra Little', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The study and application of psychological concepts and principles as related to the teaching-learning process, introduction to classroom management, measurement/evaluation, and disability awareness.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 250', 'GENERAL EDUCATIONAL PSYCHOLOGY', '14780', 'Closed', NULL, 'WB WEB', 'Tiondra Little', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The study and application of psychological concepts and principles as related to the teaching-learning process, introduction to classroom management, measurement/evaluation, and disability awareness.', ARRAY['IUB GenEd S&H credit'], NULL),
    ('EDUC-P 302', 'SCHOOL-BASED MENTAL HEALTH', '31906', 'Class Status', 'Thirteen Week', 'WB WEB', 'Hannah Kassab', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Schools are the most common location for US children to receive mental health services. Taking a social justice and prevention lens, this course provides an overview of the major professions (school counseling, school psychology, school social work) and topics focused on by those engaged in school-based mental health.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 313', 'ADOLESCENTS IN A LEARNING COMMUNITY', '1579', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 1220', 'Ciara Thomas', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on adolescent development in a school context. The course helps with understanding people and how they function in a community of learners, with particular emphasis on their interaction with others in a school environment marked by a diversity of cultural, social, and personal traits. Also the course helps the pre-service teacher in understanding and responding to adolescents'' needs in this environment.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 313', 'ADOLESCENTS IN A LEARNING COMMUNITY', '10550', 'Closed', NULL, 'WB WEB', 'Gwendolyn Davis', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course focuses on adolescent development in a school context. The course helps with understanding people and how they function in a community of learners, with particular emphasis on their interaction with others in a school environment marked by a diversity of cultural, social, and personal traits. Also the course helps the pre-service teacher in understanding and responding to adolescents'' needs in this environment.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 314', 'LIFE SPAN DEVELOPMENT', '10192', 'Closed', NULL, 'WB WEB', 'Alexa Brownell', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A survey course of human development from infancy through old age emphasizing the life span perspective of development. Major theories, current and classical research findings, and educational implications for all life stages from birth to death.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 314', 'LIFE SPAN DEVELOPMENT', '15026', 'Closed', NULL, 'WB WEB', 'Alexa Brownell', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'A survey course of human development from infancy through old age emphasizing the life span perspective of development. Major theories, current and classical research findings, and educational implications for all life stages from birth to death.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 403', 'CHILD AND ADOLESCENT TRAUMA IN APPLIED SETTINGS', '10814', 'Class Status', NULL, 'WB WEB', 'Malena Nygaard', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will cover four units: (1) the nature and definition of childhood trauma; (2) the psychosocial, biological, and developmental processes affected by trauma; (3) how educational and community-based systems can be responsive to children impacted by trauma; (4) present information for practitioners working with trauma victims.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 403', 'CHILD AND ADOLESCENT TRAUMA IN APPLIED SETTINGS', '12861', 'Closed', NULL, 'WB WEB', 'Rabbiya Shahid', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will cover four units: (1) the nature and definition of childhood trauma; (2) the psychosocial, biological, and developmental processes affected by trauma; (3) how educational and community-based systems can be responsive to children impacted by trauma; (4) present information for practitioners working with trauma victims.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 404', 'MANAGING THE BEHAVIOR OF YOUTH IN SCHOOL AND COMMUNITY SETTINGS', '9842', 'Closed', NULL, 'WB WEB', 'Gwendolyn Davis', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to help future teachers, therapists, and other youth service professionals develop the knowledge, awareness, and skills necessary to effectively manage problem behaviors in youth. Students will gain a better understanding of common childhood disorders and mental health issues that are associated with problem behaviors in youth.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 404', 'MANAGING THE BEHAVIOR OF YOUTH IN SCHOOL AND COMMUNITY SETTINGS', '11700', 'Closed', NULL, 'WB WEB', 'Scott Bellini', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is designed to help future teachers, therapists, and other youth service professionals develop the knowledge, awareness, and skills necessary to effectively manage problem behaviors in youth. Students will gain a better understanding of common childhood disorders and mental health issues that are associated with problem behaviors in youth.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 507', 'ASSESSMENT IN SCHOOLS', '32141', 'Class Status', NULL, 'OL ONLINE', 'Josh Tolbert', 1, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'Introductory assessment course for teachers and school administrators. Topics include principles of assessment, formal and informal classroom assessment instruments and methods, formative and summative assessment, interpretation and use of standardized test results, social and political issues in assessment, use of student data bases in schools.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 514', 'LIFE SPAN DEVELOPMENT: BIRTH TO DEATH', '11129', 'Class Status', 'Tu Tuesday 11:10 AM–1:40 PM', 'ED 1235', 'Charlotte Agger', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A survey course of human development from infancy through old age, emphasizing the life span perspective of development. Classical stage theorists, current popular conceptions, major research findings, and educational implications from all life stages from birth to death.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 514', 'LIFE SPAN DEVELOPMENT: BIRTH TO DEATH', '10191', 'Closed', NULL, 'WB WEB', 'Charlotte Agger', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A survey course of human development from infancy through old age, emphasizing the life span perspective of development. Classical stage theorists, current popular conceptions, major research findings, and educational implications from all life stages from birth to death.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 590', 'INDEPENDENT STUDY OR RESEARCH IN EDUCATIONAL PSYCHOLOGY', '1580', 'Class Status', NULL, NULL, 'David Shriberg', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with an Educational Psychology faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, P590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 596', 'INTERNSHIP IN SCHOOL PSYCHOLOGY I', '1581', 'Class Status', NULL, NULL, 'Megan Maloy Shepley', 10, NULL, 'Internship', '1–6', NULL, ARRAY[]::TEXT[], 'Supervised, intensive field experiences in a school setting for a full academic year for the Ed.S. students in School Psychology.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 602', 'THEORIES OF INTELLIGENCE & COGNITIVE ASSESSMENT', '12099', 'Class Status', 'Tu Tuesday 9:10 AM–11:55 AM', 'ED 2280', 'Maryellen McClain', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course content covers the theories of intelligence and cognitive abilities in addition to the assessment, scoring, and interpretation of various cognitive assessments. Students will receive training and supervised experience with cognitive assessments applicable for individuals across the lifespan, including preschool, school-aged, and adult populations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 602', 'THEORIES OF INTELLIGENCE & COGNITIVE ASSESSMENT', '31842', 'Class Status', 'M Monday 5:00 PM–6:30 PM', 'OL ONLINE', 'Melody Marley', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course content covers the theories of intelligence and cognitive abilities in addition to the assessment, scoring, and interpretation of various cognitive assessments. Students will receive training and supervised experience with cognitive assessments applicable for individuals across the lifespan, including preschool, school-aged, and adult populations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 605', 'COLLABORATION AND CONSULTATION I', '32666', 'Class Status', 'Tu Tuesday 6:30 PM–8:00 PM', 'OL ONLINE', 'Jennifer McNeany', 6, NULL, 'Seminar', '3', 'Online Class', ARRAY[]::TEXT[], 'It is imperative that school psychologists learn how to identify and utilize a range of collaboration and consultation models, knowledge and skills in understanding parent, teacher, and student needs, and effective interpersonal communication skills, including conflict resolution skills. Students will learn different theories and how to build rapport to problem-solve.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 609', 'PREVENTION, ASSESSMENT, AND INTERVENTION IN SCHOOL PSYCHOLOGY III', '32132', 'Class Status', 'Tu Tuesday 4:30 PM–6:00 PM', 'OL ONLINE', 'Melody Marley', 22, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'This course provides comprehensive training in the administration, scoring, interpretation, and real-world application of academic achievement tests.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 624', 'THE BIOLOGY OF BEHAVIOR: IMPLICATIONS FOR EDUCATIONAL & CLINICAL PRACTICE', '5138', 'Class Status', 'M Monday 8:00 AM–10:30 AM', 'ED 1084', 'Nan Mu', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Research in developmental psychobiology applied to educational practice and to clinical practice in school psychology and counseling psychology. Including the implications of genetics, endocrinology and neuroscience research in the development of attention, memory, self-regulation, language, reading, mathematics, temperament, emotions/depression, attachment, and aggression.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 624', 'THE BIOLOGY OF BEHAVIOR: IMPLICATIONS FOR EDUCATIONAL & CLINICAL PRACTICE', '12454', 'Class Status', 'W Wednesday 8:00 AM–10:30 AM', 'ED 1084', 'Nan Mu', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Research in developmental psychobiology applied to educational practice and to clinical practice in school psychology and counseling psychology. Including the implications of genetics, endocrinology and neuroscience research in the development of attention, memory, self-regulation, language, reading, mathematics, temperament, emotions/depression, attachment, and aggression.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 650', 'TOPICAL SEMINAR IN EDUCATIONAL PSYCHOLOGY: (VARIABLE TITLE)', '13582', 'Class Status', 'W Wednesday 9:35 AM–12:05 PM', 'ED 0020', 'Jesse Steinfeldt', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An intensive advanced study of research and theory on selected topics.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 650', 'TOPICAL SEMINAR IN EDUCATIONAL PSYCHOLOGY: (VARIABLE TITLE)', '11703', 'Class Status', NULL, 'WB WEB', 'Kassandra Lowery', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'An intensive advanced study of research and theory on selected topics.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 656', 'PRACTICUM IN SCHOOL PSYCHOLOGY 1', '9149', 'Class Status', NULL, 'Tu Tuesday 12:45 PM–3:15 PM Regular Academic Session 8/25/2025–12/19/2025', 'BH 135', NULL, NULL, 'Practicum', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Supervised experience in various educational settings. Use of psychometric techniques with children, advising on decisions about children, and conferences to aid children''s academic and social efficiency.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 656', 'PRACTICUM IN SCHOOL PSYCHOLOGY 1', '33911', 'Class Status', 'Aug 25', 'M Monday 6:00 PM–8:30 PM M Monday 6:00 PM–8:30 PM M Monday 6:00 PM–8:30 PM M Monday 6:00 PM–8:30 PM Regular Academic Session 8/25/2025–12/19/2025', 'OL ONLINE OL ONLINE OL ONLINE OL ONLINE', NULL, NULL, 'Practicum', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Supervised experience in various educational settings. Use of psychometric techniques with children, advising on decisions about children, and conferences to aid children''s academic and social efficiency.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 670', 'BEHAVIORAL ANALYSIS AND CONSULTATION FOR SCHOOL PSYCHOLOGISTS', '8866', 'Class Status', 'W Wednesday 9:35 AM–12:10 PM', 'ED 1220', 'Scott Bellini', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Course covers the principles and applications of applied behavioral analysis (ABA) to school settings. Emphasis will be placed on problem-solving models of consultation. The influence of culture on behavior will be examined from the perspective of ABA. Graduate standing in school psychology required.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 674', 'ADVANCED TOPICAL SEMINAR IN LEARNING SCIENCES', '10695', 'Class Status', 'M Monday 11:10 AM–1:40 PM', 'ED 1235', 'Daniel Hickey', 15, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Topical seminar for doctoral students in Learning Sciences. Possible topics include higher education, pedagogy, embodied cognition, gaming/simulation, and problem solving.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 681', 'SOCIAL JUSTICE FRAMEWORKS WITH YOUTH', '15055', 'Class Status', 'W Wednesday 12:45 PM–3:30 PM', 'ED 1230', 'Anna Merrill', 6, NULL, 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces theory and research related to multiculturalism and social justice. Primary foci are: (1) understanding social systems and structures that reinforce power differentials, privilege and oppression, (2) exploring the unique experiences of traditionally marginalized social groups; and (3) developing your capacity as an agent of social justice.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 682', 'DEVELOPMENTAL PSYCHOPATHOLOGY OF CHILDHOOD AND ADOLESCENCE', '9677', 'Class Status', 'W Wednesday 12:45 PM–3:30 PM', 'ED 1225', 'Scott Bellini', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Emphasis on a developmental approach in understanding psychopathology of childhood and adolescence. Students will learn about emotional, behavioral, developmental, and educational problems of children and adolescents over time, their stability and change, and risk and protective factors. Discussion of current research and practical applications are included.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 690', 'INDEPENDENT STUDY IN EDUCATIONAL PSYCHOLOGY', '34154', 'Class Status', NULL, NULL, 'Heather Ormiston', 1, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Reading and/or research directed by an educational psychology faculty member.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 690', 'INDEPENDENT STUDY IN EDUCATIONAL PSYCHOLOGY', '1582', 'Class Status', NULL, NULL, 'David Shriberg', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Reading and/or research directed by an educational psychology faculty member.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 692', 'PREVENTION AND INTERVENTION FOR CHILDREN AND ADOLESCENTS', '35479', 'Class Status', 'Tu Tuesday 6:15 PM–7:45 PM', 'OL ONLINE', 'Melody Marley', 12, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'The goal of this class is to prepare you to fulfill the role of school psychologist as an intervention and systems change agent for children experiencing academic, behavioral, emotional, social, and mental health difficulties.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 696', 'PRACTICUM IN SCHOOL PSYCHOLOGY 3', '8362', 'Class Status', 'Tu Tuesday 2:20 PM–4:50 PM', 'ED 1235', 'Megan Maloy Shepley', 2, NULL, 'Practicum', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The purpose of this practicum is to provide students with practical experiences that they will need to step into the role of school psychologist as an intervention and systems change agent for children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 697', 'ADVANCED PRACTICUM IN SCHOOL PSYCHOLOGY', '7632', 'Class Status', 'M Monday 4:30 PM–6:00 PM', 'ED 0020', 'Anna Merrill', 8, NULL, 'Practicum', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The Advanced Practicum in School Psychology is a practicum designed for doctoral level school psychology students who will engage in supervised school- and clinical-based experiences in applied settings and receive university-based supervision related to their cases through group supervision and case presentations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 699', 'INTERNSHIP IN SCHOOL PSYCHOLOGY II', '6342', 'Class Status', NULL, NULL, 'Megan Maloy Shepley', 20, NULL, 'Internship', '1–2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Supervised, intensive field experience. Minimally, one-half time in work directly related to public schools. Remainder may be in institutions primarily designed for providing services to children and families.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 699', 'INTERNSHIP IN SCHOOL PSYCHOLOGY II', '35810', 'Class Status', NULL, 'WB WEB', 'Anna Merrill', 2, NULL, 'Internship', '1–2', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Supervised, intensive field experience. Minimally, one-half time in work directly related to public schools. Remainder may be in institutions primarily designed for providing services to children and families.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 795', 'DISSERTATION PROPOSAL PREP', '1583', 'Class Status', NULL, NULL, 'Maryellen McClain', 9, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Educational Psychology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 795', 'DISSERTATION PROPOSAL PREP', '4256', 'Class Status', NULL, NULL, 'Maryellen McClain', 20, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Educational Psychology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 795', 'DISSERTATION PROPOSAL PREP', '9076', 'Class Status', NULL, 'WB WEB', 'Charlotte Agger', 10, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Educational Psychology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 795', 'DISSERTATION PROPOSAL PREP', '9081', 'Class Status', NULL, 'WB WEB', 'Daniel Hickey', 10, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Educational Psychology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 795', 'DISSERTATION PROPOSAL PREP', '9278', 'Class Status', NULL, NULL, 'Daniel Hickey', 10, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Educational Psychology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-P 799', 'DOCTORAL THESIS IN EDUCATIONAL PSYCHOLOGY', '1584', 'Class Status', NULL, NULL, 'Maryellen McClain', 16, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-P 799', 'DOCTORAL THESIS IN EDUCATIONAL PSYCHOLOGY', '3353', 'Class Status', NULL, NULL, 'Maryellen McClain', 99, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-P 799', 'DOCTORAL THESIS IN EDUCATIONAL PSYCHOLOGY', '9084', 'Class Status', NULL, 'WB WEB', 'Staff', 10, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-P 799', 'DOCTORAL THESIS IN EDUCATIONAL PSYCHOLOGY', '9085', 'Class Status', NULL, 'WB WEB', 'Staff', 10, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 200', 'INTRODUCTION TO SCIENTIFIC INQUIRY', '1586', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:40 PM', 'ED 3009', 'Molly Zhang, Fidelis Onwunyili', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'A lab-based course focused on developing understandings about the natural world, as well as the processes scientists use to study that world. Students in this course actively engage in scientifically-oriented questions about the natural environment, give priority to evidence in responding to questions, formulate their own explanations from evidence, connect explanations to scientific knowledge, and communicate and justify their explanations.', ARRAY['IUB GenEd N&M credit - Natural Science
Class uses IU eTexts'], NULL),
