    ('EDUC-Q 205', 'STEM FOR EDUCATORS', '10179', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:30 PM', 'ED 3105', 'Adam Maltese, Bridget Bart-Bartimeus', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces integrated topics across science, technology, engineering and mathematics. The focus is on physical science principles and how they impact the natural and built environment. The class is directed toward elementary education majors thus content mirrors that which they will need to know to teach their students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 205', 'STEM FOR EDUCATORS', '10180', 'Class Status', 'TuTh Tuesday, Thursday 9:35 AM–11:20 AM', 'ED 3105', 'Adam Maltese, Le Dolino', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces integrated topics across science, technology, engineering and mathematics. The focus is on physical science principles and how they impact the natural and built environment. The class is directed toward elementary education majors thus content mirrors that which they will need to know to teach their students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 205', 'STEM FOR EDUCATORS', '10475', 'Class Status', 'TuTh Tuesday, Thursday 3:55 PM–5:40 PM', 'ED 3105', 'Adam Maltese, Bridget Bart-Bartimeus', 17, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces integrated topics across science, technology, engineering and mathematics. The focus is on physical science principles and how they impact the natural and built environment. The class is directed toward elementary education majors thus content mirrors that which they will need to know to teach their students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 205', 'STEM FOR EDUCATORS', '11134', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:30 PM', 'ED 3105', 'Adam Maltese, Le Dolino', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces integrated topics across science, technology, engineering and mathematics. The focus is on physical science principles and how they impact the natural and built environment. The class is directed toward elementary education majors thus content mirrors that which they will need to know to teach their students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 205', 'STEM FOR EDUCATORS', '12933', 'Class Status', 'MW Monday, Wednesday 5:40 PM–7:25 PM', 'ED 3105', 'Adam Maltese, Mahnaz Zolfaghari', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course introduces integrated topics across science, technology, engineering and mathematics. The focus is on physical science principles and how they impact the natural and built environment. The class is directed toward elementary education majors thus content mirrors that which they will need to know to teach their students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 405', 'INTEGRATED SCIENCES FOR SCIENCE EDUCATION', '6430', 'Class Status', 'Tu Tuesday 5:30 PM–8:00 PM', 'ED 3015', 'Molly Zhang', 7, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Integrated science course/lab for elementary education majors with a science concentration. This capstone course is primarily a science course intended to expand previously gained science content knowledge; topic and field experiences at the discretion of the instructor.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 506', 'TEACHING SECONDARY SCHOOL SCIENCE', '5046', 'Class Status', 'M Monday 3:10 PM–5:10 PM', 'ED 3105 ED 3105', 'Adam Maltese, Gholamreza Shamsi Pour Siahmazgi', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Designed for graduate students who plan to teach biology, chemistry, earth science, general science, physical science, or physics in the junior high/middle school or secondary school.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 528', 'MAKING FOR LEARNING', '29831', 'Class Status', 'M Monday 8:00 AM–10:45 AM', 'ED 3105', 'Adam Maltese', 17, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Identification, selection, design, implementation, and evaluation of active learning strategies, focusing on making, for use by elementary, middle school, junior high and secondary school teachers.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 528', 'MAKING FOR LEARNING', '29828', 'Class Status', NULL, 'WB WEB', 'Adam Maltese', 14, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Identification, selection, design, implementation, and evaluation of active learning strategies, focusing on making, for use by elementary, middle school, junior high and secondary school teachers.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 528', 'MAKING FOR LEARNING', '35288', 'Class Status', NULL, 'OL ONLINE', 'Laticia Hequembourg', 21, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Identification, selection, design, implementation, and evaluation of active learning strategies, focusing on making, for use by elementary, middle school, junior high and secondary school teachers.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 590', 'INDEPENDENT STUDY OR RESEARCH IN SCIENCE EDUCATION', '5576', 'Class Status', NULL, NULL, 'Valarie Akerson', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with a Science Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, Q590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 601', 'PROFESSIONAL SEMINAR IN SCIENCE EDUCATION', '10354', 'Class Status', NULL, 'WB WEB', 'Valarie Akerson', 5, NULL, 'Seminar', '2–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Doctoral students in science education are introduced to the professional field by a variety of methods. Faculty members engage students in discussions about organizations, journals, conferences, and research projects. Students share their own research and receive feedback. Guest speakers present research.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 610', 'DEVELOPING AS TEACHER EDUCATORS FOR SCIENCE OR MATHEMATICS', '29848', 'Class Status', 'Th Thursday 5:30 PM–8:00 PM', 'ED 1004', 'Meredith Park Rogers', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Seminar on concepts, issues, and research-based practices associated with learning to teach elementary preservice teachers how to teach science and/or mathematics to children.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 612', 'TOPICAL SEMINAR IN SCIENCE EDUCATION', '5913', 'Class Status', NULL, 'WB WEB', 'Valarie Akerson', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Required for doctoral students in science education. Study and discussion of current topics and issues in science education. Areas might include history and philosophy inquiry, assessment, research and teacher education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 612', 'TOPICAL SEMINAR IN SCIENCE EDUCATION', '13803', 'Closed', 'W Wednesday 9:10 AM–11:55 AM', 'ED 3105', 'Adam Maltese', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Required for doctoral students in science education. Study and discussion of current topics and issues in science education. Areas might include history and philosophy inquiry, assessment, research and teacher education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Q 690', 'ADVANCED RESEARCH IN SCIENCE EDUCATION', '1591', 'Class Status', NULL, NULL, 'Valarie Akerson', 9, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Individual research participation in an attempt to determine what science (process and content) can be learned by whom and how science learning can be facilitated through teacher training or improved instructional design. Open only to advanced graduate students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 505', 'WORKSHOP IN INSTRUCTIONAL SYSTEMS TECHNOLOGY (VARIABLE TITLE)', '8749', 'Class Status', NULL, 'HD TBA', 'Elizabeth Boling', 20, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Topical workshops on selected media/technology emphasizing hands-on experience. Content will vary; e.g. multi-image, microcomputers, simulations/games. This is a service course that may or may not be applicable to IST majors depending on workshop topic and content.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 505', 'WORKSHOP IN INSTRUCTIONAL SYSTEMS TECHNOLOGY (VARIABLE TITLE)', '10005', 'Class Status', 'Three Week', 'WB WEB', 'Mike Karlin', 14, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Topical workshops on selected media/technology emphasizing hands-on experience. Content will vary; e.g. multi-image, microcomputers, simulations/games. This is a service course that may or may not be applicable to IST majors depending on workshop topic and content.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 505', 'WORKSHOP IN INSTRUCTIONAL SYSTEMS TECHNOLOGY (VARIABLE TITLE)', '11885', 'Class Status', NULL, 'WB WEB', 'Elizabeth Boling', 13, NULL, 'Lecture', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Topical workshops on selected media/technology emphasizing hands-on experience. Content will vary; e.g. multi-image, microcomputers, simulations/games. This is a service course that may or may not be applicable to IST majors depending on workshop topic and content.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 511', 'INSTRUCTIONAL AND PERFORMANCE TECHNOLOGIES FOUNDATIONS I', '3351', 'Class Status', NULL, 'WB WEB', 'Curtis Bonk', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to the field, theory, and profession of instructional and human performance technologies, including definitions, history of the field, and current trends and issues. Includes participation in discussions devoted to broadening understanding of instructional and human performance technology field and career opportunities.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 521', 'INSTRUCTIONAL DESIGN AND DEVELOPMENT I', '1592', 'Class Status', NULL, 'WB WEB', 'Kyungbin Kwon', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduces the instructional systems development process, from analysis through evaluation and implementation, and includes practice in all phases. Emphasizes design issues such as classification of learning tasks, selection of instructional strategies, and development of prototypes. Students practice the design of effective and appealing instruction based on principles from instructional theory.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 586', 'PRACTICUM IN IST', '1593', 'Class Status', NULL, NULL, 'Gamze Ozogul', 20, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The development of practical competencies in such components of instructional technology as development, production, materials evaluation, and project management and implementation. One credit hour requires approximately 48 hours of laboratory and/or independent work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 586', 'PRACTICUM IN IST', '3609', 'Class Status', NULL, 'WB WEB', 'Gamze Ozogul', 19, NULL, 'Lecture', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'The development of practical competencies in such components of instructional technology as development, production, materials evaluation, and project management and implementation. One credit hour requires approximately 48 hours of laboratory and/or independent work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 590', 'INDEPENDENT STUDY OR RESEARCH IN INSTRUCTIONAL SYSTEM TECHNOLOGY', '1594', 'Class Status', NULL, NULL, 'Gamze Ozogul', 20, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual research or study with an Instructional Systems Technology faculty member, arranged in advance or registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, R590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 590', 'INDEPENDENT STUDY OR RESEARCH IN INSTRUCTIONAL SYSTEM TECHNOLOGY', '8272', 'Class Status', NULL, 'WB WEB', 'Gamze Ozogul', 20, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual research or study with an Instructional Systems Technology faculty member, arranged in advance or registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, R590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 621', 'ANALYSIS FOR INSTRUCTION AND PERFORMANCE IMPROVEMENT', '5277', 'Class Status', 'M Monday 11:10 AM–1:40 PM', 'ED 2102', 'Thomas Brush', 6, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course centers on concepts, cases, and practices of analyzing needs in organizations. The identification of needs is a starting point for organizational and instructional development activities. The process of conducting needs analysis has a greater impact on performance improvement by attending to the context in the organization.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 621', 'ANALYSIS FOR INSTRUCTION AND PERFORMANCE IMPROVEMENT', '4491', 'Class Status', NULL, 'WB WEB', 'Thomas Brush', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course centers on concepts, cases, and practices of analyzing needs in organizations. The identification of needs is a starting point for organizational and instructional development activities. The process of conducting needs analysis has a greater impact on performance improvement by attending to the context in the organization.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 622', 'LEARNING ENVIRONMENTS DESIGN', '30252', 'Class Status', NULL, 'WB WEB', 'Curtis Bonk', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Principles and practice of environmental design. Study of interrelationships among environmental variables. Use of decision models in the design process. Design, construction, and testing of learning environments representing alternative profiles of variables.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 641', 'INSTRUCTIONAL DEVELOPMENT AND PRODUCTION PROCESS II', '8958', 'Class Status', 'TuTh Tuesday, Thursday 12:40 PM–2:10 PM', 'ED 3002', 'Elizabeth Boling', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Given an instructional problem, student teams create a design plan for an interactive product, and complete the instructional development process. Emphasizes intermediate skills in: writing, graphic design, interface design, scripting, prototyping, editing, formative evaluation, quality assurance and teamwork. Laboratory use of audio and motion video software.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 685', 'TOPICAL SEMINAR IN INSTRUCTIONAL SYSTEMS TECHNOLOGY: (VARIABLE TITLE)', '35103', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 1201', 'Kyungbin Kwon', 5, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intensive study and discussion of a specific topic of current interest in the theory and/or practice of instructional technology.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 685', 'TOPICAL SEMINAR IN INSTRUCTIONAL SYSTEMS TECHNOLOGY: (VARIABLE TITLE)', '35102', 'Class Status', NULL, 'WB WEB', 'Kyungbin Kwon', 16, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Intensive study and discussion of a specific topic of current interest in the theory and/or practice of instructional technology.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 686', 'INTERNSHIP IN IST', '1595', 'Class Status', NULL, NULL, 'Gamze Ozogul', 20, NULL, 'Internship', '3–6', NULL, ARRAY[]::TEXT[], 'To be completed during the final stages of a degree program. Provides an opportunity for students to gain professional experience in a work situation appropriate to their career goals. Students work in a cooperating agency and in consultation with an IST faculty internship coordinator.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 695', 'TOPICAL INQUIRY SEMINAR IN INSTRUCTIONAL SYSTEMS TECHNOLOGY: (VARIABLE TITLE)', '1596', 'Class Status', 'F Friday 11:10 AM–1:40 PM', 'ED 1084', 'Gamze Ozogul', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Critical examination of current inquiry in an emphasis area in instructional systems technology. Specific topics will vary. Students complete a research project. Course serves as early IST inquiry experience for doctoral students.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 699', 'SPECIALIST PROJECT IN INSTRUCTIONAL SYSTEMS TECHNOLOGY', '1597', 'Class Status', NULL, NULL, 'Gamze Ozogul', 20, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual instructional technology project serving as the culminating experience in the specialist degree program. The project will be presented and evaluated at a final meeting with the student''s advisory committee.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 711', 'READINGS IN INSTRUCTIONAL TECHNOLOGY', '1598', 'Class Status', 'W Wednesday 12:45 PM–3:30 PM', 'ED 2271', 'Ugur Kale', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Selected advanced readings in instructional technology and related fields with guidance from members of the IST faculty.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 711', 'READINGS IN INSTRUCTIONAL TECHNOLOGY', '5503', 'Class Status', NULL, 'WB WEB', 'Ugur Kale', 11, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Selected advanced readings in instructional technology and related fields with guidance from members of the IST faculty.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 741', 'INSTRUCTIONAL DEVELOPMENT AND PRODUCTION III', '8957', 'Class Status', 'TuTh Tuesday, Thursday 12:40 PM–2:10 PM', 'ED 3002', 'Elizabeth Boling', 4, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Working with a client, student teams conduct the entire instructional design and development process. Emphasizes advanced skills in: writing, graphic design, interface design, scripting, prototyping, editing, formative evaluation, quality assurance and teamwork. Laboratory use of multimedia software development tools as required.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 795', 'DISSERTATION PROPOSAL PREP', '4580', 'Class Status', 'F Friday 12:45 PM–3:30 PM', 'ED 1201', 'Elizabeth Boling', 18, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Instructional Systems Technology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 795', 'DISSERTATION PROPOSAL PREP', '6360', 'Class Status', NULL, 'WB WEB', 'Elizabeth Boling', 14, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in Instructional Systems Technology. Students must have the consent of a dissertation director or prospective dissertation director. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 799', 'DOCTORAL DISSERTATION IN IST', '1599', 'Class Status', NULL, NULL, 'Gamze Ozogul', 89, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'For Ph.D., reflects the ability to conduct an original piece of research. For Ed.D., may involve significant work in evaluation, program development, description, or other suitable studies of professional practice.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 799', 'DOCTORAL DISSERTATION IN IST', '3300', 'Class Status', NULL, NULL, 'Gamze Ozogul', 90, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'For Ph.D., reflects the ability to conduct an original piece of research. For Ed.D., may involve significant work in evaluation, program development, description, or other suitable studies of professional practice.', ARRAY[]::TEXT[], NULL),
    ('EDUC-R 799', 'DOCTORAL DISSERTATION IN IST', '8537', 'Class Status', NULL, 'WB WEB', 'Gamze Ozogul', 70, NULL, 'Independent Study', '1–15', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'For Ph.D., reflects the ability to conduct an original piece of research. For Ed.D., may involve significant work in evaluation, program development, description, or other suitable studies of professional practice.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 303', 'TOPICS IN SECONDARY EDUCATION:', '3676', 'Class Status', 'W Wednesday 5:45 PM–8:15 PM', 'ED 3017', 'Lori Burch', 3, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Various topics will be covered in this course in order to incorporate timely professional issues in the secondary curriculum.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 303', 'TOPICS IN SECONDARY EDUCATION:', '3678', 'Class Status', 'Th Thursday 8:00 AM–10:30 AM', 'ED 3017', 'Alexander Cuenca, Jaeun Won', 9, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Various topics will be covered in this course in order to incorporate timely professional issues in the secondary curriculum.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 303', 'TOPICS IN SECONDARY EDUCATION:', '3682', 'Class Status', 'W Wednesday 4:20 PM–5:10 PM', 'ED 3105', 'Adam Maltese, Gholamreza Shamsi Pour Siahmazgi', 5, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Various topics will be covered in this course in order to incorporate timely professional issues in the secondary curriculum.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 303', 'TOPICS IN SECONDARY EDUCATION:', '5149', 'Class Status', NULL, 'WB WEB', 'Erin McNeill', 6, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Various topics will be covered in this course in order to incorporate timely professional issues in the secondary curriculum.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 503', 'SECONDARY SCHOOL CURRICULUM', '10444', 'Class Status', NULL, 'WB WEB', 'Lara Christoun', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Designed to provide an overview for the teacher of the basic theories underlying the secondary school curriculum as well as an examination of the subject areas, problems, trends, and challenges for the future and significant research in the field.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 508', 'PROBLEMS IN SECONDARY EDUCATION', '4197', 'Class Status', 'W Wednesday 4:20 PM–5:10 PM', 'ED 3105', 'Adam Maltese, Gholamreza Shamsi Pour Siahmazgi', 12, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Group analysis of a common problem in the field of secondary education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 508', 'PROBLEMS IN SECONDARY EDUCATION', '4198', 'Class Status', 'W Wednesday 5:45 PM–8:15 PM', 'ED 3017', 'Lori Burch', 2, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Group analysis of a common problem in the field of secondary education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-S 519', 'ADV STUDY TCH SEC SC SOC STDS', '3319', 'Class Status', 'Th Thursday 2:20 PM–4:50 PM', 'ED 3275', 'Anneliese Paulson', 12, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-T 450', 'CULTURAL/COMMUNITY FORCES AND THE SCHOOLS', '1606', 'Class Status', NULL, NULL, 'Laura Stachowski', 2, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'This course provides the student with an opportunity to analyze community forces and/or cultures by direct, residential participation in community-related activities so as to modify their instructional strategies within educational settings.', ARRAY[]::TEXT[], NULL),
    ('EDUC-T 550', 'CULTURAL/COMMUNITY FORCES AND THE SCHOOLS', '1607', 'Class Status', NULL, NULL, 'Laura Stachowski', 144, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Promotes modification of instructional strategies within diverse educational settings by providing opportunities to analyze community forces and cultures through cultural orientation workshops and seminars, culturally focused readings, direct residential participation in community-related activities, and site-based culture/strategies reports.', ARRAY[]::TEXT[], NULL),
    ('EDUC-T 550', 'CULTURAL/COMMUNITY FORCES AND THE SCHOOLS', '1608', 'Class Status', NULL, NULL, 'Laura Stachowski', 144, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Promotes modification of instructional strategies within diverse educational settings by providing opportunities to analyze community forces and cultures through cultural orientation workshops and seminars, culturally focused readings, direct residential participation in community-related activities, and site-based culture/strategies reports.', ARRAY[]::TEXT[], NULL),
    ('EDUC-T 550', 'CULTURAL/COMMUNITY FORCES AND THE SCHOOLS', '5151', 'Class Status', NULL, NULL, 'Laura Stachowski', 133, NULL, 'Independent Study', '3', NULL, ARRAY[]::TEXT[], 'Promotes modification of instructional strategies within diverse educational settings by providing opportunities to analyze community forces and cultures through cultural orientation workshops and seminars, culturally focused readings, direct residential participation in community-related activities, and site-based culture/strategies reports.', ARRAY[]::TEXT[], NULL),
    ('EDUC-T 590', 'INDEPENDENT STUDY OR RESEARCH IN URBAN/MULTICULTURAL EDUCATION', '1609', 'Class Status', NULL, NULL, 'Laura Stachowski', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with an Urban/Multicultural Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, T590 should not be sued for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 208', 'TRAINING FOR PARAPROFESSIONALS IN STUDENT AFFAIRS', '12867', 'Class Status', 'W Wednesday 5:30 PM–8:00 PM', 'ED 1120', 'Molly Lambert', 19, NULL, 'Lecture', '1–2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will focus on the development of specific skills for paraprofessional student staff such as resident advisors (RAs) and student orientation leaders. Topics may include theories of student development, leadership skills, crisis intervention, and confrontation skills, and information about appropriate University policies and resources.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 208', 'TRAINING FOR PARAPROFESSIONALS IN STUDENT AFFAIRS', '8454', 'Class Status', NULL, 'WB WEB', 'Danielle DeSawal', 19, NULL, 'Lecture', '1–2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course will focus on the development of specific skills for paraprofessional student staff such as resident advisors (RAs) and student orientation leaders. Topics may include theories of student development, leadership skills, crisis intervention, and confrontation skills, and information about appropriate University policies and resources.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 212', 'CURRENT ISSUES IN UNDERGRADUATE LIFE', '12878', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 2275', 'Corryn Anderson, Juliana Statile', 5, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course is a topical seminar which will address issues of interest to new undergraduates. Topics may include student diversity and campus life, the role and status of college women, or college students and alcohol.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 215', 'FOUNDATIONS FOR UNDERGRADUATE SUCCESS AT RESEARCH UNIVERSITIES', '10704', 'Class Status', 'Th Thursday 9:35 AM–10:50 AM', 'ED 2271', 'Yih Tsao', 2, 'Discussion', 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will challenge students to critically think about themselves and their roles as learners at a research university; develop cognitive, study, and communication skills necessary for academic success as a college student; and, engage in personal, educational, and career exploration strategies leading to clear plans for success at Indiana University and beyond.', ARRAY[]::TEXT[], NULL),
