    ('EDUC-U 215', 'FOUNDATIONS FOR UNDERGRADUATE SUCCESS AT RESEARCH UNIVERSITIES', '10838', 'Closed', 'Th Thursday 3:55 PM–5:10 PM', 'ED 1230', 'Patrick Smith', 0, 'Discussion', 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will challenge students to critically think about themselves and their roles as learners at a research university; develop cognitive, study, and communication skills necessary for academic success as a college student; and, engage in personal, educational, and career exploration strategies leading to clear plans for success at Indiana University and beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 215', 'FOUNDATIONS FOR UNDERGRADUATE SUCCESS AT RESEARCH UNIVERSITIES', '12908', 'Closed', 'Th Thursday 3:55 PM–5:10 PM', 'ED 3015', 'Lauren Mixon', 0, 'Discussion', 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will challenge students to critically think about themselves and their roles as learners at a research university; develop cognitive, study, and communication skills necessary for academic success as a college student; and, engage in personal, educational, and career exploration strategies leading to clear plans for success at Indiana University and beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 215', 'FOUNDATIONS FOR UNDERGRADUATE SUCCESS AT RESEARCH UNIVERSITIES', '14242', 'Closed', 'Th Thursday 9:35 AM–10:50 AM', 'ED 2025', 'Lindsey Arnold', 0, 'Discussion', 'Discussion', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The course will challenge students to critically think about themselves and their roles as learners at a research university; develop cognitive, study, and communication skills necessary for academic success as a college student; and, engage in personal, educational, and career exploration strategies leading to clear plans for success at Indiana University and beyond.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 320', 'TODAY''S COLLEGE STUDENT', '12072', 'Closed', 'Thirteen Week', 'WB WEB', 'Danielle DeSawal', 0, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course will explore the characteristics of today''s college student. As a class we will interrogate the following question: Who are today''s college students? In order to unpack this question further we will examine how the identities, demographics, and experiences of college students changed over time to create the "contemporary" college student. Additionally, we will seek to understand current trends in higher education and their implications on today''s college student.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 495', 'SEMINAR IN LEADERSHIP TRAINING', '30465', 'Class Status', 'Th Thursday 6:40 PM–8:20 PM', 'ED 0101', 'Ryan Kelly', 2, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The theory and practice of group work, leadership techniques, communication, human relations, problem solving, and decision making. Cases emphasize the role of the student leader in the total university community.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 495', 'SEMINAR IN LEADERSHIP TRAINING', '5410', 'Class Status', NULL, 'WB WEB', 'Molly Lambert', 15, NULL, 'Lecture', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The theory and practice of group work, leadership techniques, communication, human relations, problem solving, and decision making. Cases emphasize the role of the student leader in the total university community.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 548', 'STUDENT DEVELOPMENT THEORY AND RESEARCH', '1610', 'Class Status', 'Tu Tuesday 12:45 PM–3:30 PM', 'ED 1225', 'Cindy Ann Kilgo', 15, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Overview of the social psychological and student affairs literature related to college student development. Relationships between student characteristics and college outcomes are examined. Applications of psychosocial, cognitive developmental, and person-environment interaction theories to student affairs work are considered in-depth.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 549', 'ENVIROMENTAL THEORY AND ASSESSMENT', '9697', 'Class Status', 'Tu Tuesday 11:10 AM–1:40 PM', 'TE F104', 'Lucy LePeau', 16, NULL, 'Lecture', '3', 'TETER QUAD', ARRAY[]::TEXT[], 'Selected environmental theories are examined (e.g. human aggregate, physical/architectural, campus ecology, cultural, perceptual). Various environmental assessment approaches for use in postsecondary settings are reviewed. Strategies for humanizing campus environments are examined with a particular emphasis on members of historically underrepresented groups.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 560', 'INTERNSHIP IN STUDENT AFFAIRS', '14186', 'Class Status', NULL, NULL, 'Danielle DeSawal', 9, NULL, 'Internship', '1–3', 'Online Class', ARRAY[]::TEXT[], 'Relates theory to practice through supervised experience in student affairs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 560', 'INTERNSHIP IN STUDENT AFFAIRS', '30471', 'Class Status', NULL, 'OL ONLINE', 'Danielle DeSawal', 9, NULL, 'Internship', '1–3', 'Online Class', ARRAY[]::TEXT[], 'Relates theory to practice through supervised experience in student affairs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 590', 'INDEPENDENT STUDY OR RESEARCH IN COLLEGE STUDENT PERSONNEL ADMINISTRATION', '1611', 'Class Status', NULL, NULL, 'Danielle DeSawal', 9, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual research or study with a College Student Personnel Administration faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, U590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 590', 'INDEPENDENT STUDY OR RESEARCH IN COLLEGE STUDENT PERSONNEL ADMINISTRATION', '6419', 'Class Status', NULL, 'WB WEB', 'Danielle DeSawal', 5, NULL, 'Independent Study', '1–3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual research or study with a College Student Personnel Administration faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, U590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-U 599', 'MA THESIS COL STUDENT PER ADM', '1612', 'Class Status', NULL, NULL, 'Danielle DeSawal', 10, NULL, 'Research', '3', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-V 551', 'COMPARATIVE EDUCATION 1', '29880', 'Class Status', NULL, 'WB WEB', 'Mark Baildon', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introduction to the comparative method in the study of educational issues and systems in different societies. Provides students with conceptual and methodological tools from the field of education and related disciplines-such as sociology, political science, anthropology, and economics-for studying societal school systems in depth and making international and cross-cultural comparisons.', ARRAY[]::TEXT[], NULL),
    ('EDUC-V 553', 'TRAVEL STUDY', '29881', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 5, NULL, 'Activity', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Student will complete a travel study that examines education in an international or cultural domestic context in relation to a chosen comparative educational emphasis or theme. Travel study must be arranged by the student and approved by advisor and instructor of record.', ARRAY[]::TEXT[], NULL),
    ('EDUC-V 625', 'PRACTICUM IN INTERNATIONAL AND COMPARATIVE EDUCATION', '29882', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 5, NULL, 'Practice', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Supervised practical experience in settings where international and comparative education curriculum, policy, or practice is being analyzed, formulated or implemented. Practicum must be arranged by student and approved by supervisor, academic advisor, and course instructor.', ARRAY[]::TEXT[], NULL),
    ('EDUC-V 626', 'GLOBAL EDUCATION POLICY AND REFORM', '29885', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course provides a critical overview of education policy studies and an examination of the social, cultural, and political fields in which policy is created and enacted. The course explores a range of contemporary education policy and reform issues globally.', ARRAY[]::TEXT[], NULL),
    ('EDUC-V 637', 'TOPICAL SEMINAR IN COMPARATIVE EDUCATION', '29883', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Current issues, developments and concerns bearing upon international and comparative education. Specific topics vary each semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-V 690', 'INDEPENDENT STUDY OR RESEARCH IN COMPARATIVE EDUCATION', '29884', 'Class Status', NULL, 'WB WEB', 'Patricia Kubow', 5, NULL, 'Independent Study', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Individual study arranged in advance of registration.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 200', 'TEACHING WITH TECHNOLOGY', '8961', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'ED 2015', 'Susan Drumm', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Required of all students pursuing teacher education. Introduction to technology integration. Hands-on experience with educational apps and resources to support transferrable student learning.', ARRAY[]::TEXT[], NULL),
