    ('EDUC-W 200', 'TEACHING WITH TECHNOLOGY', '4299', 'Closed', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'ED 2015', 'Susan Drumm, Leonardo Alba Lopez', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Required of all students pursuing teacher education. Introduction to technology integration. Hands-on experience with educational apps and resources to support transferrable student learning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 204', 'RESOURCES FOR BLENDED AND ONLINE LEARNING', '11688', 'Class Status', NULL, 'WB WEB', 'Laura Christie', 14, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Students explore tools and resources to foster learning in virtual settings. Students will investigate multiple instructional platforms, and examine many web-based and mobile applications, all through a lens of best pedagogical practices. Through exposure, practice, and instructional integration, students will build their own personal toolbox of technology integration resources.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 450', 'INTERNSHIP IN BLENDED AND ONLINE TEACHING', '12748', 'Class Status', NULL, NULL, 'Abigail Dutcher', 5, NULL, 'Practicum', '3', NULL, ARRAY[]::TEXT[], 'Students will work alongside one or more practicing K12 virtual instructors, putting into practice the pedagogical knowledge and skills acquired in in previous courses. Internship experiences will include planning, design, and implementation of virtual lessons, including student assessment.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 500', 'PROFESSIONAL DEVELOPMENT CONFERENCE: SPECIFIC TITLE', '1615', 'Class Status', NULL, NULL, 'Laura Stachowski', 10, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Conference to meet specific professional needs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 505', 'PROFESSIONAL DEVELOPMENT CONFERENCE: SPECIFIC TITLE', '1616', 'Class Status', NULL, NULL, 'Laura Stachowski', 90, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], 'Workshop to meet specific professional needs.', ARRAY[]::TEXT[], NULL),
    ('EDUC-W 531', 'TECHNOLOGY FOR TEACHING AND LEARNING', '35489', 'Class Status', NULL, 'OL ONLINE', 'Ju Park', 6, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'A survey of technology used for teaching and learning which explores technologies in learning environments. Students will critically examine topics such as 21st century learning, new literacies, digital divides, digital citizens, technology in classrooms, web-based tools, mobile technologies, game-based learning, and technology innovations. Students will evaluate educational technology tools and engage in social networking and collaborative learning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 101', 'TECHNIQUES IN TEXTBOOK READING', '1618', 'Class Status', 'TuTh Tuesday, Thursday 11:35 AM–12:25 PM', 'ED 1201', 'Andrew Koke, Italia Ramos', 10, NULL, 'Lecture', '2', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Instruction and guided practice in techniques for learning from printed materials. Emphasis is on graining information from text and practical retrieval and discussion of concepts. Much of the work is done on an individual basis.', ARRAY[]::TEXT[], NULL),
