    ('EDUC-X 156', 'COLLEGE AND LIFE LONG LEARNING', '6671', 'Class Status', 'Tu Tuesday 3:10 PM–5:10 PM', 'CU 304', 'Andrew Koke, Dorcas Miao', 1, NULL, 'Lecture', '2', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'Students attend 11 public workshops on a wide range of reading, study, and learning skills topics offered by the Student Academic Center and meet for 13 individual conferences with instructors or peer mentors to discuss concepts and application. Emphasis is developing on positive and eliminating negative behaviors.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 156', 'COLLEGE AND LIFE LONG LEARNING', '7122', 'Class Status', 'W Wednesday 3:10 PM–5:10 PM', 'CU 304', 'Andrew Koke, Sarah Viater', 4, NULL, 'Lecture', '2', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'Students attend 11 public workshops on a wide range of reading, study, and learning skills topics offered by the Student Academic Center and meet for 13 individual conferences with instructors or peer mentors to discuss concepts and application. Emphasis is developing on positive and eliminating negative behaviors.', ARRAY[]::TEXT[], NULL),
