    ('EDUC-X 158', 'CULTURE OF COLLEGE', '4361', 'Class Status', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'CU 304', 'Molly Burke, Taiwo Ogundapo', 5, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 158', 'CULTURE OF COLLEGE', '10281', 'Class Status', 'TuTh Tuesday, Thursday 2:20 PM–3:35 PM', 'AC C118', 'Molly Burke, Chloe Maginity', 5, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 158', 'CULTURE OF COLLEGE', '14962', 'Class Status', 'MW Monday, Wednesday 12:45 PM–2:00 PM', 'ED 1210', 'Zhaoyi Zhang, Molly Burke', 3, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 158', 'CULTURE OF COLLEGE', '14963', 'Class Status', 'MW Monday, Wednesday 2:20 PM–3:35 PM', 'ED 1210', 'Zhaoyi Zhang, Molly Burke', 8, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 158', 'CULTURE OF COLLEGE', '1628', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'CU 304', 'Molly Burke, Taiwo Ogundapo', 0, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 158', 'CULTURE OF COLLEGE', '10280', 'Closed', 'TuTh Tuesday, Thursday 12:45 PM–2:00 PM', 'ED 2275', 'Molly Burke, Chloe Maginity', 0, NULL, 'Lecture', '3', 'STUDENT SERVICES', ARRAY[]::TEXT[], 'This course presents a comprehensive view of college as a culture to be learned and understood while developing academic and personal skills that support success. It is intended for students on academic probation or entering students who would benefit from sustained support for a full semester.', ARRAY[]::TEXT[], NULL),
    ('EDUC-X 599', 'MASTER''S THESIS IN EDUCATION', '3305', 'Class Status', NULL, NULL, 'Erik Jacobson', 1, NULL, 'Independent Study', '1–6', NULL, ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 402', 'INTRODUCTION TO STATISTICS FOR BEHAVIORAL AND EDUCATIONAL SCIENCES', '30332', 'Closed', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'BH 016', 'Preston Botter', 0, NULL, 'Lecture', '3', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Course is designed to develop a working understanding of the fundamental concepts used in descriptive and inferential statistics. The purpose is to understand the use of statistics in educational research as a tool to analyze and interpret data. Students will learn appropriate statistical procedures, calculate statistics, and perform statistical tests.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 435', 'PROGRAM EVALUATION FOR APPLIED EDUCATIONAL PROFESSIONS', '14172', 'Closed', 'TuTh Tuesday, Thursday 9:35 AM–10:50 AM', 'ED 2275', 'Danielle Layton', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This undergraduate capstone inquiry course engages students in conducting a small scale evaluation by consulting with a relevant organization or business. Students will begin with a simulated evaluation study organized according to thread. By the second half of the semester, students will be involved in group-conducted local evaluations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 500', 'COMPUTER LABORATORY AND CONSULTATION FOR EDUCATIONAL INQUIRY', '3454', 'Class Status', 'Tu Tuesday 8:00 AM–10:30 AM', 'ED 1204', 'Preston Botter', 9, NULL, 'Laboratory', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This laboratory course is designed to accompany specific courses in educational inquiry. Use of research software, interpretation of analysis results, and conceptual discussion of corresponding concepts and principles are included in this laboratory. This course will include course-related consultation. The management and use of large data sets may be included in some laboratory offerings.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 500', 'COMPUTER LABORATORY AND CONSULTATION FOR EDUCATIONAL INQUIRY', '3273', 'Class Status', 'Thirteen Week', 'WB WEB', 'Katie Haus', 2, NULL, 'Laboratory', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This laboratory course is designed to accompany specific courses in educational inquiry. Use of research software, interpretation of analysis results, and conceptual discussion of corresponding concepts and principles are included in this laboratory. This course will include course-related consultation. The management and use of large data sets may be included in some laboratory offerings.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 500', 'COMPUTER LABORATORY AND CONSULTATION FOR EDUCATIONAL INQUIRY', '5144', 'Class Status', 'Thirteen Week', 'WB WEB', 'Justin Paulsen', 11, NULL, 'Laboratory', '1', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This laboratory course is designed to accompany specific courses in educational inquiry. Use of research software, interpretation of analysis results, and conceptual discussion of corresponding concepts and principles are included in this laboratory. This course will include course-related consultation. The management and use of large data sets may be included in some laboratory offerings.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 502', 'INTERMEDIATE STATISTICS APPLIED TO EDUCATION', '1629', 'Class Status', 'Thirteen Week', 'WB WEB', 'Leslie Rutkowski', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 502', 'INTERMEDIATE STATISTICS APPLIED TO EDUCATION', '5143', 'Class Status', 'Thirteen Week', 'WB WEB', 'Dubravka Svetina Valdivia', 11, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 510', 'ACTION RESEARCH I', '35488', 'Class Status', NULL, 'OL ONLINE', 'Natalie Pough', 14, NULL, 'Lecture', '3', 'Online Class', ARRAY[]::TEXT[], 'An introduction to the basic philosophy and methods of action research. Students will design an action research project and write a proposal. In this class, you will learn how to conduct action research. You will learn how to select an area of focus; collect data; organize, analyze and interpret data; and take action based on your findings. You will plan an action research study and write a formal proposal for that study.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '8699', 'Class Status', 'Thirteen Week', 'WB WEB', 'David Rutkowski', 1, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '13001', 'Class Status', 'Thirteen Week', 'WB WEB', 'Lex Weber', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '34505', 'Class Status', 'Non Standard Session', 'WB WEB', 'Justin Paulsen', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '34529', 'Class Status', 'Thirteen Week', 'WB WEB', 'Staff', 20, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '31752', 'Class Status', NULL, 'OL ONLINE', 'Anita Benna', 4, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '35656', 'Class Status', NULL, 'OL ONLINE', 'Anita Benna', 6, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 520', 'STRATEGIES FOR EDUCATIONAL INQUIRY', '36662', 'Class Status', NULL, 'OL ONLINE', 'James Barbre', 20, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Introductory course intended to orient beginning graduate students to the conduct of social science inquiry in general and educational inquiry in particular and to acquaint them with key terms and generally accepted procedures in qualitative and quantitative inquiry.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 521', 'METHODOLOGICAL APPROACHES TO EDUCATIONAL INQUIRY', '4273', 'Class Status', 'W Wednesday 12:45 PM–3:30 PM', 'ED 2277', 'Lucinda Carspecken', 2, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to the various methodological approaches to the conduct of social sciences inquiry in general and educational inquiry in particular. Focus on the epistemological implications of methodological choices.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 527', 'EDUCATIONAL ASSESSMENT AND PSYCHOLOGICAL MEASUREMENT', '1630', 'Closed', 'Thirteen Week', 'WB WEB', 'Dubravka Svetina Valdivia', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Theoretical foundations for assessing educational and psychological constructs, with application to tests and alternative assessment procedures; methods for estimating reliability and validity; and techniques for scale construction, including attitude, personality, interest, aptitude, and performance.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 535', 'EVALUATION MODELS AND TECHNIQUES', '14173', 'Closed', 'Thirteen Week', 'WB WEB', 'David Rutkowski', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'An overview of evaluation as an inquiry process, including a discussion of the history of evaluation and the state of the art. Frameworks and models for planning evaluation studies are discussed and applications are demonstrated. Criteria for evaluating studies, steps for writing evaluation proposals and reports, and techniques for the collection of information are discussed.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 590', 'INDEPENDENT STUDY OR RESEARCH IN INQUIRY METHODOLOGY', '1631', 'Class Status', NULL, NULL, 'Dubravka Svetina Valdivia', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with an Inquiry faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, Y590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 600', 'METHODOLOGICAL IMPLICATIONS OF SOCIAL AND PSYCHOLOGICAL THEORIES', '30322', 'Class Status', 'M Monday 12:45 PM–3:30 PM', 'ED 1084', 'Phil Carspecken', 3, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Introduction to social psychological theories that inform current methodological theory and practice including those developed by Freud, Piaget, Levi-Strauss, Webber and Marx. This introduction forms the basis of an exploration of methodological concepts such as validity and inference in terms of their social and psychological foundations.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 604', 'MULTIVARIATE ANLS IN EDUC RES', '1632', 'Class Status', 'TuTh Tuesday, Thursday 11:10 AM–12:25 PM', 'ED 1230', 'Sijia Huang', 9, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], NULL, ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 611', 'QUALITATIVE INQUIRY IN EDUCATION', '7638', 'Class Status', 'Tu Tuesday 12:45 PM–3:30 PM', 'ED 3015', 'Lucinda Carspecken', 5, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examination of qualitative approaches to educational inquiry (e.g. case study, naturalistic inquiry, educational anthropology, educational connoisseurship and criticism). Exploration of methods for collecting and analyzing qualitative data, criteria for field studies, and approaches to writing up field studies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 611', 'QUALITATIVE INQUIRY IN EDUCATION', '4564', 'Closed', 'Thirteen Week', 'WB WEB', 'Vivek Vellanki', 0, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Examination of qualitative approaches to educational inquiry (e.g. case study, naturalistic inquiry, educational anthropology, educational connoisseurship and criticism). Exploration of methods for collecting and analyzing qualitative data, criteria for field studies, and approaches to writing up field studies.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 630', 'NARRATIVE THEORY AND INQUIRY', '11132', 'Class Status', 'Thirteen Week', 'WB WEB', 'Beth Hatt', 2, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Examines narrative theory and its connection to narrative approaches to inquiry. Explores the use of narrative in qualitative inquiry, and practices methods of collecting and analyzing narrative data.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 637', 'CATEGORICAL DATA ANALYSIS', '14180', 'Class Status', 'MW Monday, Wednesday 9:35 AM–10:50 AM', 'ED 0101', 'Leslie Rutkowski', 16, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'The analysis of cross-classified categorical data. Loglinear models, regression models in which the response variable is binary, ordinal, nominal, or discrete. Logit, probit, multinomial logit models; logistic and Poisson regression.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 640', 'ANALYZING QUALITATIVE DATA', '34843', 'Class Status', 'Thirteen Week', 'WB WEB', 'Beth Hatt', 3, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'This course 1) presents a range of approaches to qualitative analysis, 2) defines the distinct terminology used when describing qualitative analyses, 3) articulates the procedures common to particular approaches to qualitative data analysis, and 4) describes how theory guides the interpretation process.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 650', 'TOPICS IN EDUCATIONAL INQUIRY METHODOLOGY', '34045', 'Class Status', 'Tu Tuesday 11:30 AM–2:00 PM', 'ED 3115', 'Vivek Vellanki', 1, NULL, 'Seminar', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Advanced study of research and theory on selected topics in qualitative or quantitative inquiry methodology.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 660', 'AFFINITY RESEARCH GROUP', '15223', 'Class Status', 'Thirteen Week', 'HD TBA', 'Vivek Vellanki', 6, NULL, 'Seminar', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Study and Research support groups formed on the basis of mutual interests to generate new curriculum and research projects integrating previous course work under the guidance of a faculty member. The work of these groups could continue over the course of several semesters to develop research papers, presentations, books or conduct empirical research as a team.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 660', 'AFFINITY RESEARCH GROUP', '36713', 'Class Status', 'Thirteen Week', 'HD TBA', 'Dubravka Svetina Valdivia', 2, NULL, 'Seminar', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Study and Research support groups formed on the basis of mutual interests to generate new curriculum and research projects integrating previous course work under the guidance of a faculty member. The work of these groups could continue over the course of several semesters to develop research papers, presentations, books or conduct empirical research as a team.', ARRAY[]::TEXT[], NULL),
