    ('EDUC-Y 660', 'AFFINITY RESEARCH GROUP', '35113', 'Class Status', 'Thirteen Week', 'WB WEB', 'Lucinda Carspecken', 2, NULL, 'Seminar', '3', 'BLDG NOT ASSIGNED', ARRAY[]::TEXT[], 'Study and Research support groups formed on the basis of mutual interests to generate new curriculum and research projects integrating previous course work under the guidance of a faculty member. The work of these groups could continue over the course of several semesters to develop research papers, presentations, books or conduct empirical research as a team.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 690', 'ADVANCED INDEPENDENT STUDY IN INQUIRY METHODOLOGY', '5617', 'Class Status', 'Thirteen Week', NULL, 'Dubravka Svetina Valdivia', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research with an Inquiry faculty member on an advanced methodology topic, arranged prior to registration. A short proposal should be submitted during the first week specifying the scope of the project, completion date, and products. Y690 is not for material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 795', 'DISSERTATION PROPOSAL PREP', '4490', 'Class Status', 'Thirteen Week', NULL, 'Dubravka Svetina Valdivia', 19, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in program areas in education which do not currently offer such a course. Students must have the consent of a dissertation director or prospective director to enroll. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 795', 'DISSERTATION PROPOSAL PREP', '5139', 'Class Status', 'Thirteen Week', NULL, 'Dubravka Svetina Valdivia', 10, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'This course is for the development of a dissertation proposal in program areas in education which do not currently offer such a course. Students must have the consent of a dissertation director or prospective director to enroll. Students should be finished or nearly finished with program course work.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 799', 'DOCTORAL THESIS IN INQUIRY METHODOLOGY', '5140', 'Class Status', 'Thirteen Week', NULL, 'Dubravka Svetina Valdivia', 38, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Credit may be earned over a period of several semesters. The thesis may be an organized scientific contribution or a comprehensive analysis of theory and practice in a specific area.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Y 799', 'DOCTORAL THESIS IN INQUIRY METHODOLOGY', '5141', 'Class Status', 'Thirteen Week', NULL, 'Dubravka Svetina Valdivia', 98, NULL, 'Independent Study', '1–12', NULL, ARRAY[]::TEXT[], 'Credit may be earned over a period of several semesters. The thesis may be an organized scientific contribution or a comprehensive analysis of theory and practice in a specific area.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 204', 'APPLIED THEATRE', '11188', 'Class Status', 'Th Thursday 12:45 PM–3:15 PM', 'ED 3115', 'Gustave Weltsek', 8, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'This course was developed for the larger university population to explore how aspects of Drama, Theatre and performance practice and theory may be used within multiple aspects of society from the physical and mental health industry, to business, science and education. Student exploration of Applied Theatre engages them in hands on and theoretical examinations of interpersonal leaning through multiple, physical, vocal, written and visual arts based approaches. Students will develop methods to identify areas within their particular disciplines where these strategies may be applied to maximize the potential for human personal, social and physical growth, cognitive development and socially equitable business production.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 533', 'CHILD ART: UNDERSTANDING CHILDREN AS MAKERS AND READERS OF IMAGES', '11442', 'Class Status', 'MW Monday, Wednesday 3:55 PM–5:10 PM', 'ED 3125', 'Susan Livingston', 1, NULL, 'Lecture', '3', 'WENDELL W. WRIGHT EDUCATION BU', ARRAY[]::TEXT[], 'Graduate level introduction to the nature, meanings and development of visual/artistic expressions and aesthetic responses from childhood through adolescence. Students will analyze children''s artworks and reactions to images through readings, case studies, and field experiences, and consider implications for promoting artistic and aesthetic growth. Open to all graduate students.', ARRAY['Class uses IU eTexts'], NULL),
    ('EDUC-Z 550', 'TOPICAL SEMINAR IN ART EDUCATION', '37272', 'Closed', NULL, 'WB WEB', 'Gustave Weltsek', 0, NULL, 'Lecture', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Advanced study of selected topics in art education drawing upon resources which are uniquely available or particularly pertinent to the given topic.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 590', 'INDEPENDENT STUDY OR RESEARCH IN ART EDUCATION', '1633', 'Class Status', NULL, NULL, 'Gustave Weltsek', 9, NULL, 'Independent Study', '1–3', NULL, ARRAY[]::TEXT[], 'Individual research or study with an Art Education faculty member, arranged in advance of registration. A one or two page written proposal should be submitted to the instructor during the first week of the term specifying the scope of the project, project activities, meeting times, completion date, and student product(s). Ordinarily, Z590 should not be used for the study of material taught in a regularly scheduled course.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 633', 'TRAUMA-INFORMED, COMMUNITY-BASED ART EDUCATION', '32569', 'Class Status', 'Thirteen Week', 'WB WEB', 'Heidi Davis-Soylu', 8, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Intended for educators and facilitators in school or community contexts, this course presents arts-based approaches to working with youth and adults who are anxious about or have experienced events of trauma. Readings, process-modeling activities, and materials are drawn from museum studies, arts education, art therapy, neuroaesthetics, and social emotional learning.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 700', 'PRACTICUM IN ART EDUCATION', '6421', 'Class Status', NULL, 'WB WEB', 'Marjorie Manifold', 7, NULL, 'Practicum', '1–6', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Training experiences for prospective researchers; or supervised college teaching experiences; or administrative internships in some area of art education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 750', 'TOPICAL DOCTORAL SEMINAR IN ART EDUCATION: VARIABLE TITLE', '12122', 'Class Status', NULL, 'WB WEB', 'Kevin Tavin', 7, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Required for Art Education doctoral students. Critical examination of a range of contemporary issues and topics, including those related to learning, curriculum, pedagogy, visual culture or equity in art education.', ARRAY[]::TEXT[], NULL),
    ('EDUC-Z 750', 'TOPICAL DOCTORAL SEMINAR IN ART EDUCATION: VARIABLE TITLE', '34292', 'Class Status', NULL, 'WB WEB', 'Marjorie Manifold', 2, NULL, 'Seminar', '3', 'WEB-BASED CLASS', ARRAY[]::TEXT[], 'Required for Art Education doctoral students. Critical examination of a range of contemporary issues and topics, including those related to learning, curriculum, pedagogy, visual culture or equity in art education.', ARRAY[]::TEXT[], NULL),
    ('ENG-D 600', 'HISTORY OF THE ENGLISH LANGUAGE', '33030', 'Class Status', NULL, 'OL ONLINE', 'Frederick DiCamilla', 1, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'Survey of the evolution of the English language from its earliest stages to the present, with reference to its external history and to its phonology, morphology, syntax, and vocabulary.', ARRAY[]::TEXT[], NULL),
    ('ENG-G 601', 'MEDIEVAL LANGUAGES', '30425', 'Class Status', 'MW Monday, Wednesday 11:10 AM–12:25 PM', 'BH 106', 'Joey McMullen', 5, NULL, 'Lecture', '4', 'BALLANTINE HALL', ARRAY[]::TEXT[], 'Introductory language instruction in the vernacular medieval languages of the British Isles. Course may cover Old English, Middle English, Old Irish, or Middle Welsh.', ARRAY[]::TEXT[], NULL),
    ('ENG-G 660', 'STYLISTICS', '32724', 'Class Status', NULL, 'OL ONLINE', 'William Allegrezza', 2, NULL, 'Lecture', '4', 'Online Class', ARRAY[]::TEXT[], 'Survey of traditional and linguistic approaches to the study of prose and poetic style. Attention to the verbal characteristics of texts, what they reflect about the author, and how they affect the reader.', ARRAY[]::TEXT[], NULL),
    ('ENG-G 901', 'ADVANCED RESEARCH', '1634', 'Class Status', NULL, NULL, 'Jesse Molesworth', 70, NULL, 'Research', '6', NULL, ARRAY[]::TEXT[], 'Available to graduate students who have completed all course requirements for their doctorates, have passed doctoral qualifying examinations, and have the requisite number of degree credit hours, this course provides the advanced research student with a forum for sharing ideas and problems under the supervision of a senior researcher.', ARRAY[]::TEXT[], NULL),
